import { useState, useEffect, useRef } from "react";
import { useNavigate } from "react-router-dom";
import { cn } from "@/lib/utils";
import { useAuth } from "@/contexts/AuthContext";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import { useTranslation } from "react-i18next";
import mapboxgl from "mapbox-gl";
import "mapbox-gl/dist/mapbox-gl.css";
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Checkbox } from "@/components/ui/checkbox";
import { Switch } from "@/components/ui/switch";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import { Upload, X, MapPin, Globe, Store, Clock, Phone, Globe as WebIcon, Key, ImageIcon, ShoppingBag, UtensilsCrossed, User, Building2, Link, Film, ChefHat, Search, UserPlus, UserMinus, Loader2, FileText, BookOpen, CalendarDays, Hotel } from "lucide-react";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Card, CardContent } from "@/components/ui/card";
import { supabase } from "@/integrations/supabase/client";
import { useToast } from "@/hooks/use-toast";
import { useQueryClient } from "@tanstack/react-query";
import { useUserRole } from "@/hooks/useUserRole";
import { DishImageManager } from "@/components/admin/DishImageManager";
import { ChefRecommendedDishesEditor } from "@/components/admin/ChefRecommendedDishesEditor";
import { RichTextEditor } from "@/components/admin/RichTextEditor";
import { TypeCombobox } from "@/components/admin/TypeCombobox";
import { useAllRestaurantTypes } from "@/hooks/useAllRestaurantTypes";
import { useBrands, Brand } from "@/hooks/useBrands";
import { RestaurantVideoManager } from "@/components/admin/RestaurantVideoManager";
import IChingRegenerateSection from "@/components/admin/IChingRegenerateSection";
import { LandmarkSpotsEditor, ScenicSpot } from "@/components/admin/LandmarkSpotsEditor";
import { LandmarkInfoEditor, LandmarkInfo } from "@/components/admin/LandmarkInfoEditor";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import i18n from "@/i18n/config";

interface VideoItem {
  url: string;
  title_zh?: string;
  title_en?: string;
  title_pt?: string;
  poster_url?: string;
  duration?: number;
}

const restaurantSchema = z.object({
  name: z.string().min(1, i18n.t("validation.nameRequired")),
  key_id: z.string().optional(),
  type: z.array(z.string()).min(1, i18n.t("validation.typeRequired")).max(3, i18n.t("validation.typeMaximum")),
  description: z.string().optional(),
  announcement: z.string().optional(),
  address: z.string().min(1, i18n.t("validation.addressRequired")),
  lat: z.number(),
  lng: z.number(),
  phone: z.string().optional(),
  // website_url kept in DB but no longer editable in form
  official_website: z.string().optional(),
  takeaway_url: z.string().optional(),
  
  visible: z.boolean().default(true),
  show_takeaway_button: z.boolean().default(true),
  
  show_website_button: z.boolean().default(true),
  show_ghost_intro: z.boolean().default(true),
});

type RestaurantFormData = z.infer<typeof restaurantSchema>;

interface RestaurantFormDialogProps {
  restaurant?: any;
  trigger: React.ReactNode;
}

interface DayHours {
  open: string;
  close: string;
  closed: boolean;
  splitShift?: boolean; // 分段营业模式
  open2?: string; // 第二时段开门时间
  close2?: string; // 第二时段关门时间
}

const DAYS = ["monday", "tuesday", "wednesday", "thursday", "friday", "saturday", "sunday"];

export function RestaurantFormDialog({ restaurant, trigger }: RestaurantFormDialogProps) {
  const { t } = useTranslation();
  const { toast } = useToast();
  const { user } = useAuth();

  // Notify admin when shallow merchant tries to enable buttons
  const handleShallowMerchantButtonRequest = async (buttonType: 'takeaway' | 'booking' | 'website') => {
    toast({
      title: t("admin.shallowMerchantButtonRequestTitle", "需要管理员开启"),
      description: t("admin.shallowMerchantButtonRequestDesc", "已通知管理员，请等待管理员为您开启此功能"),
    });

    try {
      // Get admin users and send notification
      const { data: adminUsers } = await supabase
        .from("user_roles")
        .select("user_id")
        .eq("role", "admin");

      if (adminUsers && adminUsers.length > 0) {
        const restaurantName = restaurant?.name || t("admin.unknownRestaurant", "未知餐厅");
        const { data: profile } = await supabase
          .from("profiles")
          .select("display_name")
          .eq("id", user?.id || "")
          .maybeSingle();
        const merchantName = profile?.display_name || user?.email || t("admin.unknownMerchant", "未知商家");
        const featureNames: Record<string, string> = {
          takeaway: t("admin.showTakeawayButton"),
          website: t("admin.showWebsiteButton"),
        };
        const featureName = featureNames[buttonType] || buttonType;

        const notifications = adminUsers.map((admin) => ({
          user_id: admin.user_id,
          type: "system" as const,
          title: t("admin.merchantFeatureRequestTitle", "商家请求开启功能"),
          content: `${merchantName} → ${restaurantName}: ${featureName}`,
          link: "/admin/restaurants",
        }));

        await supabase.from("notifications").insert(notifications);
      }
    } catch (err) {
      console.error("Failed to notify admin:", err);
    }
  };
  const queryClient = useQueryClient();
  const navigateToEdit = useNavigate();
  const { isAdmin, isShallowMerchant } = useUserRole();
  const { data: existingTypes } = useAllRestaurantTypes();
  const { data: brands } = useBrands();
  const [open, setOpen] = useState(false);
  const [allowMerchantEditWebsite, setAllowMerchantEditWebsite] = useState<boolean>(restaurant?.allow_merchant_edit_website || false);
  const [isChain, setIsChain] = useState<boolean>(restaurant?.is_chain || false);
  const [storeLevel, setStoreLevel] = useState<string>(restaurant?.store_level || 'shell');
  const [associatedMerchants, setAssociatedMerchants] = useState<{ user_id: string; display_name: string; email: string }[]>([]);
  const [merchantSearchQuery, setMerchantSearchQuery] = useState("");
  const [merchantSearchResults, setMerchantSearchResults] = useState<{ id: string; display_name: string; email: string; role: string }[]>([]);
  const [isSearchingMerchants, setIsSearchingMerchants] = useState(false);

  // Fetch associated merchants when dialog opens
  useEffect(() => {
    if (open && restaurant?.id) {
      const fetchMerchants = async () => {
        const { data: mrData } = await supabase
          .from("merchant_restaurants")
          .select("user_id")
          .eq("restaurant_id", restaurant.id);
        if (mrData && mrData.length > 0) {
          const userIds = mrData.map(m => m.user_id);
          const { data: profiles } = await supabase
            .from("profiles")
            .select("id, display_name")
            .in("id", userIds);
          // Get emails via get_user_email function
          const merchants = await Promise.all(
            mrData.map(async (m) => {
              const profile = profiles?.find(p => p.id === m.user_id);
              const { data: emailData } = await supabase.rpc("get_user_email", { _user_id: m.user_id });
              return {
                user_id: m.user_id,
                display_name: profile?.display_name || t("admin.unknown", "未知"),
                email: emailData || "",
              };
            })
          );
          setAssociatedMerchants(merchants);
        } else {
          setAssociatedMerchants([]);
        }
      };
      fetchMerchants();
    } else if (!open) {
      setAssociatedMerchants([]);
    }
  }, [open, restaurant?.id]);

  // When store level changes to non-complete, auto-disable features
  const handleStoreLevelChange = (newLevel: string) => {
    // Prevent switching to shell if there are associated merchants
    if (newLevel === 'shell' && associatedMerchants.length > 0) {
      toast({
        title: t("admin.cannotSwitch", "无法切换"),
        description: t("admin.cannotSwitchToShell", "该商店有关联用户，不可设为空壳商店。请先解除所有关联用户"),
        variant: "destructive",
      });
      return;
    }
    setStoreLevel(newLevel);
    if (newLevel !== 'complete') {
      setValue("show_takeaway_button", false);
      // Hotel template keeps website button independent of store level
      if (template !== 'hotel') {
        setValue("show_website_button", false);
      }
      setAllowMerchantEditWebsite(false);
    }
  };

  // Search merchants/users to assign
  const searchMerchants = async (query: string) => {
    if (query.length < 2) {
      setMerchantSearchResults([]);
      return;
    }
    setIsSearchingMerchants(true);
    try {
      // Search by display_name - exact matches first, then partial
      const [{ data: exactMatches }, { data: partialMatches }] = await Promise.all([
        supabase
          .from("profiles")
          .select("id, display_name")
          .ilike("display_name", query)
          .limit(10),
        supabase
          .from("profiles")
          .select("id, display_name")
          .ilike("display_name", `%${query}%`)
          .limit(30),
      ]);

      // Merge: exact first, then partial (deduplicated)
      const exactIds = new Set((exactMatches || []).map(p => p.id));
      const nameResults = [
        ...(exactMatches || []),
        ...(partialMatches || []).filter(p => !exactIds.has(p.id)),
      ];

      // Also try to find by email using edge function or direct search
      // Since we can't query auth.users directly, we search profiles and check emails
      const existingIds = associatedMerchants.map(m => m.user_id);
      const uniqueProfiles = nameResults.filter(p => !existingIds.includes(p.id));

      // Get role and email for each found profile
      const results = await Promise.all(
        uniqueProfiles.map(async (p) => {
          const [emailRes, roleRes] = await Promise.all([
            supabase.rpc("get_user_email", { _user_id: p.id }),
            supabase.from("user_roles").select("role").eq("user_id", p.id).maybeSingle(),
          ]);
          return {
            id: p.id,
            display_name: p.display_name || t("admin.unknown", "未知"),
            email: emailRes.data || "",
            role: roleRes.data?.role || "user",
          };
        })
      );

      // If query looks like an email, also search by email
      if (query.includes("@") || query.includes(".")) {
        // Fetch broader set and filter by email
        const { data: broadProfiles } = await supabase
          .from("profiles")
          .select("id, display_name")
          .limit(100);
        
        if (broadProfiles) {
          const alreadyFoundIds = new Set(results.map(r => r.id));
          const candidates = broadProfiles.filter(p => !alreadyFoundIds.has(p.id) && !existingIds.includes(p.id));
          
          // Check emails in batches
          const emailResults = await Promise.all(
            candidates.map(async (p) => {
              const { data: emailData } = await supabase.rpc("get_user_email", { _user_id: p.id });
              return { ...p, email: emailData || "" };
            })
          );
          
          const emailMatches = emailResults.filter(r => r.email.toLowerCase().includes(query.toLowerCase()));
          
          for (const match of emailMatches.slice(0, 10)) {
            const { data: roleData } = await supabase.from("user_roles").select("role").eq("user_id", match.id).maybeSingle();
            results.push({
              id: match.id,
              display_name: match.display_name || t("admin.unknown", "未知"),
              email: match.email,
              role: roleData?.role || "user",
            });
          }
        }
      }

      // Sort: merchants and supervisors first
      const rolePriority: Record<string, number> = { merchant: 0, supervisor: 1, admin: 2, user: 3 };
      results.sort((a, b) => (rolePriority[a.role] ?? 3) - (rolePriority[b.role] ?? 3));
      setMerchantSearchResults(results);
    } catch (err) {
      console.error("Search merchants error:", err);
    } finally {
      setIsSearchingMerchants(false);
    }
  };

  // Assign merchant to restaurant
  const assignMerchant = async (userId: string) => {
    if (!restaurant?.id) {
      // For new stores, just add to local state (will be linked after insert)
      const result = merchantSearchResults.find(r => r.id === userId);
      if (result) {
        setAssociatedMerchants(prev => [...prev, { user_id: userId, display_name: result.display_name, email: result.email }]);
        setMerchantSearchResults(prev => prev.filter(r => r.id !== userId));
      }
      toast({ title: t("admin.added", "已添加"), description: t("admin.userWillBeLinked", "用户将在保存后关联到此餐厅") });
      return;
    }
    try {
      const { error } = await supabase.from("merchant_restaurants").insert({
        user_id: userId,
        restaurant_id: restaurant.id,
      });
      if (error) throw error;
      
      // Auto-upgrade role based on store level
      const { data: existingRole } = await supabase
        .from("user_roles")
        .select("role")
        .eq("user_id", userId)
        .maybeSingle();
      
      if (!existingRole || existingRole.role === 'user') {
        // Insert or update role to merchant
        if (existingRole) {
          await supabase.from("user_roles").update({ role: "merchant" }).eq("user_id", userId);
        } else {
          await supabase.from("user_roles").insert({ user_id: userId, role: "merchant" });
        }
      }

      // Set merchant_type based on store level: basic → shallow, complete → null
      const merchantType = storeLevel === 'basic' ? 'shallow' : null;
      await supabase.from("profiles").update({ merchant_type: merchantType }).eq("id", userId);
      
      // Refresh associated merchants
      const result = merchantSearchResults.find(r => r.id === userId);
      if (result) {
        setAssociatedMerchants(prev => [...prev, { user_id: userId, display_name: result.display_name, email: result.email }]);
        setMerchantSearchResults(prev => prev.filter(r => r.id !== userId));
      }
      
      const roleLabel = storeLevel === 'basic' ? t("admin.storeLevelBasic") : t("admin.storeLevelComplete");
      toast({ title: t("admin.linked", "已关联"), description: t("admin.userLinkedAndUpgraded", "用户已关联到此餐厅并自动升级角色") });
    } catch (err: any) {
      toast({ title: t("admin.linkFailed", "关联失败"), description: err.message, variant: "destructive" });
    }
  };

  // Unassign merchant from restaurant
  const unassignMerchant = async (userId: string) => {
    if (!restaurant?.id) {
      // For new stores, just remove from local state
      setAssociatedMerchants(prev => prev.filter(m => m.user_id !== userId));
      toast({ title: t("admin.removed", "已移除"), description: t("admin.userRemovedFromList", "用户已从列表中移除") });
      return;
    }
    try {
      const { error } = await supabase
        .from("merchant_restaurants")
        .delete()
        .eq("user_id", userId)
        .eq("restaurant_id", restaurant.id);
      if (error) throw error;
      setAssociatedMerchants(prev => prev.filter(m => m.user_id !== userId));
      toast({ title: t("admin.unlinked", "已解除关联"), description: t("admin.userRemovedFromRestaurant", "用户已从此餐厅移除") });
    } catch (err: any) {
      toast({ title: t("admin.operationFailed", "操作失败"), description: err.message, variant: "destructive" });
    }
  };

  const [brandId, setBrandId] = useState<string | null>(restaurant?.brand_id || null);
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [imagePreview, setImagePreview] = useState<string | null>(restaurant?.image_url || null);
  const [coverImageFile, setCoverImageFile] = useState<File | null>(null);
  const [coverImagePreview, setCoverImagePreview] = useState<string | null>(restaurant?.cover_image_url || null);
  const [ownerAvatarFile, setOwnerAvatarFile] = useState<File | null>(null);
  const [ownerAvatarPreview, setOwnerAvatarPreview] = useState<string | null>(restaurant?.owner_avatar_url || null);
  const [bannerFile, setBannerFile] = useState<File | null>(null);
  const [bannerPreview, setBannerPreview] = useState<string | null>(restaurant?.banner_url || null);
  const [ownerBio, setOwnerBio] = useState<string>(restaurant?.owner_bio || "");
  const [ownerName, setOwnerName] = useState<string>((restaurant as any)?.owner_name || "");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [activeSection, setActiveSection] = useState<string>("basic");
  
  // Video management state
  const [bannerMediaType, setBannerMediaType] = useState<'image' | 'video'>(
    (restaurant?.banner_media_type as 'image' | 'video') || 'image'
  );
  const [promoVideoUrl, setPromoVideoUrl] = useState<string>(restaurant?.promo_video_url || "");
  const [promoVideoPoster, setPromoVideoPoster] = useState<string>(restaurant?.promo_video_poster || "");
  const [videos, setVideos] = useState<VideoItem[]>(() => {
    if (restaurant?.videos && Array.isArray(restaurant.videos)) {
      return restaurant.videos as VideoItem[];
    }
    return [];
  });
  const [isGeocoding, setIsGeocoding] = useState(false);
  const mapContainer = useRef<HTMLDivElement>(null);
  const map = useRef<mapboxgl.Map | null>(null);
  const marker = useRef<mapboxgl.Marker | null>(null);
  const [openingHours, setOpeningHours] = useState<Record<string, DayHours>>(() => {
    const defaultHours: Record<string, DayHours> = {};
    DAYS.forEach(day => {
      defaultHours[day] = { 
        open: "12:00", 
        close: "23:00", 
        closed: false,
        splitShift: false,
        open2: "19:00",
        close2: "23:00"
      };
    });
    if (restaurant?.opening_hours) {
      return { ...defaultHours, ...restaurant.opening_hours };
    }
    return defaultHours;
  });
  
  const isMichelinRestaurant = restaurant?.template === 'michelin' || Boolean(restaurant?.michelin_stars);
  const isHotelRestaurant = restaurant?.template === 'hotel';

  // State for template type
  const [template, setTemplate] = useState<string>(isMichelinRestaurant ? 'michelin' : (restaurant?.template || 'default'));

  // Landmark-specific state
  const [scenicSpots, setScenicSpots] = useState<ScenicSpot[]>(() => {
    if (restaurant?.scenic_spots && Array.isArray(restaurant.scenic_spots)) {
      return restaurant.scenic_spots as ScenicSpot[];
    }
    return [];
  });
  const [landmarkInfo, setLandmarkInfo] = useState<LandmarkInfo>(() => {
    if (restaurant?.landmark_info && typeof restaurant.landmark_info === 'object') {
      return restaurant.landmark_info as LandmarkInfo;
    }
    return {};
  });
  
  // Reset all local state when dialog opens or restaurant prop changes
  useEffect(() => {
    if (open) {
      setAllowMerchantEditWebsite(restaurant?.allow_merchant_edit_website || false);
      setIsChain(restaurant?.is_chain || false);
      setStoreLevel(restaurant?.store_level || 'shell');
      setBrandId(restaurant?.brand_id || null);
      setImageFile(null);
      setImagePreview(restaurant?.image_url || null);
      setCoverImageFile(null);
      setCoverImagePreview(restaurant?.cover_image_url || null);
      setOwnerAvatarFile(null);
      setOwnerAvatarPreview(restaurant?.owner_avatar_url || null);
      setBannerFile(null);
      setBannerPreview(restaurant?.banner_url || null);
      setOwnerBio(restaurant?.owner_bio || "");
      setOwnerName((restaurant as any)?.owner_name || "");
      setBannerMediaType((restaurant?.banner_media_type as 'image' | 'video') || 'image');
      setPromoVideoUrl(restaurant?.promo_video_url || "");
      setPromoVideoPoster(restaurant?.promo_video_poster || "");
      setVideos(restaurant?.videos && Array.isArray(restaurant.videos) ? restaurant.videos as VideoItem[] : []);
      setTemplate(restaurant?.template || 'default');
      setScenicSpots(restaurant?.scenic_spots && Array.isArray(restaurant.scenic_spots) ? restaurant.scenic_spots as ScenicSpot[] : []);
      setLandmarkInfo(restaurant?.landmark_info && typeof restaurant.landmark_info === 'object' ? restaurant.landmark_info as LandmarkInfo : {});

      // Auto-set type for landmarks
      const currentTemplate = restaurant?.template || 'default';
      if (currentTemplate === 'landmark') {
        setTypes(["landmark"]);
        setValue('type', ["landmark"]);
      }

      // Reset opening hours
      const defaultHours: Record<string, DayHours> = {};
      DAYS.forEach(day => {
        defaultHours[day] = { open: "12:00", close: "23:00", closed: false, splitShift: false, open2: "19:00", close2: "23:00" };
      });
      setOpeningHours(restaurant?.opening_hours ? { ...defaultHours, ...restaurant.opening_hours } : defaultHours);

      // Reset types
      if (restaurant?.type && Array.isArray(restaurant.type)) {
        setTypes([...restaurant.type]);
      } else {
        setTypes([""]);
      }

      // Reset form values
      if (restaurant) {
        setValue('name', restaurant.name);
        setValue('key_id', restaurant.key_id || "");
        setValue('type', Array.isArray(restaurant.type) ? restaurant.type : [restaurant.type]);
        setValue('description', restaurant.description || "");
        setValue('announcement', restaurant.announcement_zh || "");
        setValue('address', restaurant.address);
        setValue('lat', typeof restaurant.lat === 'number' && !isNaN(restaurant.lat) ? restaurant.lat : 38.7223);
        setValue('lng', typeof restaurant.lng === 'number' && !isNaN(restaurant.lng) ? restaurant.lng : -9.1393);
        setValue('phone', restaurant.phone || "");
        // website_url no longer editable
        setValue('official_website', restaurant.official_website || "");
        setValue('takeaway_url', restaurant.takeaway_url || "");
        setValue('visible', restaurant.visible ?? true);
        setValue('show_takeaway_button', restaurant.show_takeaway_button ?? true);
        setValue('show_website_button', restaurant.show_website_button ?? (restaurant.template === 'hotel' ? false : true));
        setValue('show_ghost_intro', restaurant.show_ghost_intro ?? true);
      }
    }
  }, [open, restaurant]);

  // State for multiple types (1-3 tags)
  const [types, setTypes] = useState<string[]>(() => {
    if (restaurant?.type && Array.isArray(restaurant.type)) {
      return restaurant.type;
    }
    return [""];
  });

  const {
    register,
    handleSubmit,
    formState: { errors },
    setValue,
    watch,
    trigger: triggerValidation,
  } = useForm<RestaurantFormData>({
    resolver: zodResolver(restaurantSchema),
    defaultValues: restaurant ? {
      name: restaurant.name,
      key_id: restaurant.key_id || "",
      type: Array.isArray(restaurant.type) ? restaurant.type : [restaurant.type],
      description: restaurant.description || "",
      announcement: restaurant.announcement_zh || "",
      address: restaurant.address,
      lat: typeof restaurant.lat === 'number' && !isNaN(restaurant.lat) ? restaurant.lat : 38.7223,
      lng: typeof restaurant.lng === 'number' && !isNaN(restaurant.lng) ? restaurant.lng : -9.1393,
      phone: restaurant.phone || "",
      official_website: restaurant.official_website || "",
      takeaway_url: restaurant.takeaway_url || "",
      visible: restaurant.visible ?? true,
      show_takeaway_button: restaurant.show_takeaway_button ?? true,
      show_website_button: restaurant.show_website_button ?? (restaurant.template === 'hotel' ? false : true),
      show_ghost_intro: restaurant.show_ghost_intro ?? true,
    } : {
      name: "",
      key_id: "",
      type: [""],
      description: "",
      announcement: "",
      address: "",
      lat: 38.7223,
      lng: -9.1393,
      phone: "",
      official_website: "",
      takeaway_url: "",
      visible: true,
      show_takeaway_button: true,
      show_website_button: true,
      show_ghost_intro: true,
    },
  });

  // Helper to show validation errors
  const showValidationErrors = () => {
    const errorMessages: string[] = [];
    
    if (errors.name) errorMessages.push(t("admin.fieldName"));
    if (errors.type) errorMessages.push(t("admin.fieldType"));
    if (errors.address) errorMessages.push(t("admin.fieldAddress"));
    if (errors.lat || errors.lng) errorMessages.push(t("admin.fieldLocation"));
    
    if (errorMessages.length > 0) {
      toast({
        title: t("admin.validationFailed"),
        description: t("admin.missingFields") + ": " + errorMessages.join(", "),
        variant: "destructive",
      });
    }
  };
  
  const addType = () => {
    if (types.length < 3) {
      setTypes([...types, ""]);
    }
  };
  
  const removeType = (index: number) => {
    if (types.length > 1) {
      setTypes(types.filter((_, i) => i !== index));
    }
  };
  
  const updateType = (index: number, value: string) => {
    const newTypes = [...types];
    newTypes[index] = value;
    setTypes(newTypes);
    
    // Update form values
    setValue('type', newTypes.filter(Boolean));
  };

  const lat = watch("lat");
  const lng = watch("lng");
  const visible = watch("visible");
  const showTakeawayButton = watch("show_takeaway_button");
  
  const showWebsiteButton = watch("show_website_button");
  const showGhostIntro = watch("show_ghost_intro");

  // Helper function to check if coordinates are valid
  const isValidCoordinate = (lat: number, lng: number) => {
    return typeof lat === 'number' && typeof lng === 'number' && 
           !isNaN(lat) && !isNaN(lng) && 
           isFinite(lat) && isFinite(lng);
  };

  // Initialize map when dialog opens and location section is active
  useEffect(() => {
    if (!open) {
      // Clean up map when dialog closes
      if (map.current) {
        map.current.remove();
        map.current = null;
        marker.current = null;
      }
      return;
    }

    // Only initialize when location section is active
    if (activeSection !== "location") return;

    // Don't initialize if already exists
    if (map.current) {
      // Just resize in case container changed
      setTimeout(() => map.current?.resize(), 100);
      return;
    }

    const mapboxToken = import.meta.env.VITE_MAPBOX_TOKEN;
    if (!mapboxToken) {
      console.error("Mapbox token not found");
      toast({
        title: t("common.error"),
        description: t("admin.mapboxTokenNotConfigured"),
        variant: "destructive",
      });
      return;
    }

    // Wait for container to be rendered
    const initMap = () => {
      if (!mapContainer.current) {
        console.error("Map container not found");
        return;
      }

      try {
        mapboxgl.accessToken = mapboxToken;

        // Use valid coordinates or default to Lisbon
        const centerLng = isValidCoordinate(lat, lng) ? lng : -9.1393;
        const centerLat = isValidCoordinate(lat, lng) ? lat : 38.7223;

        map.current = new mapboxgl.Map({
          container: mapContainer.current,
          style: "mapbox://styles/mapbox/light-v11",
          center: [centerLng, centerLat],
          zoom: 15,
        });

        // Disable scroll zoom by default (require Ctrl key)
        map.current.scrollZoom.disable();

        map.current.on('load', () => {
          if (!map.current) return;
          
          // Add marker after map loads only if coordinates are valid
          if (isValidCoordinate(lat, lng)) {
            marker.current = new mapboxgl.Marker({ draggable: true })
              .setLngLat([lng, lat])
              .addTo(map.current);

            marker.current.on("dragend", () => {
              const lngLat = marker.current!.getLngLat();
              setValue("lng", lngLat.lng);
              setValue("lat", lngLat.lat);
            });
          }

          // Resize to fit container - multiple attempts for dialog animations
          map.current.resize();
          setTimeout(() => map.current?.resize(), 100);
          setTimeout(() => map.current?.resize(), 300);
          setTimeout(() => map.current?.resize(), 600);
        });

        // Enable scroll zoom only when Ctrl key is pressed
        const handleWheel = (e: WheelEvent) => {
          if (e.ctrlKey || e.metaKey) {
            map.current?.scrollZoom.enable();
          } else {
            map.current?.scrollZoom.disable();
          }
        };

        mapContainer.current.addEventListener('wheel', handleWheel);

        map.current.on("click", (e) => {
          const { lng: clickLng, lat: clickLat } = e.lngLat;
          setValue("lng", clickLng);
          setValue("lat", clickLat);
          
          if (marker.current) {
            marker.current.setLngLat([clickLng, clickLat]);
          } else if (map.current) {
            marker.current = new mapboxgl.Marker({ draggable: true })
              .setLngLat([clickLng, clickLat])
              .addTo(map.current);
            marker.current.on("dragend", () => {
              const lngLat = marker.current!.getLngLat();
              setValue("lng", lngLat.lng);
              setValue("lat", lngLat.lat);
            });
          }
        });

        map.current.on('error', (e) => {
          console.error("Map error:", e);
        });
      } catch (error) {
        console.error("Failed to initialize map:", error);
      }
    };

    // Give time for dialog animation and container to render
    const timer = setTimeout(initMap, 300);
    // Additional resize after longer delay for slow dialog animations
    const timer2 = setTimeout(() => map.current?.resize(), 1000);

    return () => {
      clearTimeout(timer);
      clearTimeout(timer2);
    };
  }, [open, activeSection]);

  // Geocode address to coordinates using Mapbox
  const handleGeocode = async (query: string) => {
    const mapboxToken = import.meta.env.VITE_MAPBOX_TOKEN;
    if (!mapboxToken || !query.trim()) return;
    
    setIsGeocoding(true);
    try {
      const res = await fetch(
        `https://api.mapbox.com/geocoding/v5/mapbox.places/${encodeURIComponent(query)}.json?access_token=${mapboxToken}&limit=1`
      );
      const data = await res.json();
      if (data.features?.length > 0) {
        const [resultLng, resultLat] = data.features[0].center;
        setValue("lat", resultLat);
        setValue("lng", resultLng);
        
        // Update map view and marker
        if (map.current) {
          map.current.flyTo({ center: [resultLng, resultLat], zoom: 16 });
          if (marker.current) {
            marker.current.setLngLat([resultLng, resultLat]);
          } else {
            marker.current = new mapboxgl.Marker({ draggable: true })
              .setLngLat([resultLng, resultLat])
              .addTo(map.current);
            marker.current.on("dragend", () => {
              const lngLat = marker.current!.getLngLat();
              setValue("lng", lngLat.lng);
              setValue("lat", lngLat.lat);
            });
          }
        }
        
        toast({ title: t("common.success"), description: t("admin.geocodeSuccess", "已定位到地址") });
      } else {
        toast({ title: t("common.error"), description: t("admin.geocodeNotFound", "未找到该地址"), variant: "destructive" });
      }
    } catch (err) {
      console.error("Geocode error:", err);
      toast({ title: t("common.error"), description: t("admin.geocodeFailed", "地址搜索失败"), variant: "destructive" });
    } finally {
      setIsGeocoding(false);
    }
  };

  useEffect(() => {
    if (marker.current && map.current && isValidCoordinate(lat, lng)) {
      marker.current.setLngLat([lng, lat]);
      map.current.setCenter([lng, lat]);
    }
  }, [lat, lng]);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setImageFile(file);
      const reader = new FileReader();
      reader.onloadend = () => {
        setImagePreview(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleCoverImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setCoverImageFile(file);
      const reader = new FileReader();
      reader.onloadend = () => {
        setCoverImagePreview(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleOwnerAvatarChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setOwnerAvatarFile(file);
      const reader = new FileReader();
      reader.onloadend = () => {
        setOwnerAvatarPreview(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleBannerChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setBannerFile(file);
      const reader = new FileReader();
      reader.onloadend = () => {
        setBannerPreview(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const uploadImage = async (): Promise<string | null> => {
    if (!imageFile) return restaurant?.image_url || null;

    const fileExt = imageFile.name.split(".").pop();
    const fileName = `${Math.random()}.${fileExt}`;
    const filePath = `${fileName}`;

    const { error: uploadError } = await supabase.storage
      .from("restaurant-images")
      .upload(filePath, imageFile);

    if (uploadError) {
      throw uploadError;
    }

    const { data: { publicUrl } } = supabase.storage
      .from("restaurant-images")
      .getPublicUrl(filePath);

    return publicUrl;
  };

  const uploadCoverImage = async (): Promise<string | null> => {
    if (!coverImageFile) return restaurant?.cover_image_url || null;

    const fileExt = coverImageFile.name.split(".").pop();
    const fileName = `cover_${Math.random()}.${fileExt}`;
    const filePath = `${fileName}`;

    const { error: uploadError } = await supabase.storage
      .from("restaurant-images")
      .upload(filePath, coverImageFile);

    if (uploadError) {
      throw uploadError;
    }

    const { data: { publicUrl } } = supabase.storage
      .from("restaurant-images")
      .getPublicUrl(filePath);

    return publicUrl;
  };

  const uploadOwnerAvatar = async (): Promise<string | null> => {
    if (!ownerAvatarFile) return restaurant?.owner_avatar_url || null;

    const fileExt = ownerAvatarFile.name.split(".").pop();
    const fileName = `owner_${Math.random()}.${fileExt}`;
    const filePath = `${fileName}`;

    const { error: uploadError } = await supabase.storage
      .from("restaurant-images")
      .upload(filePath, ownerAvatarFile);

    if (uploadError) {
      throw uploadError;
    }

    const { data: { publicUrl } } = supabase.storage
      .from("restaurant-images")
      .getPublicUrl(filePath);

    return publicUrl;
  };

  const uploadBanner = async (): Promise<string | null> => {
    if (!bannerFile) return restaurant?.banner_url || null;

    const fileExt = bannerFile.name.split(".").pop();
    const fileName = `banner_${Math.random()}.${fileExt}`;
    const filePath = `${fileName}`;

    const { error: uploadError } = await supabase.storage
      .from("restaurant-images")
      .upload(filePath, bannerFile);

    if (uploadError) {
      throw uploadError;
    }

    const { data: { publicUrl } } = supabase.storage
      .from("restaurant-images")
      .getPublicUrl(filePath);

    return publicUrl;
  };


  const onSubmit = async (data: RestaurantFormData) => {
    // Validate: complete and basic stores must have associated merchants (skip for landmark)
    if (template !== 'landmark' && isAdmin && (storeLevel === 'basic' || storeLevel === 'complete') && associatedMerchants.length === 0) {
      toast({
        title: t("admin.cannotSave", "无法保存"),
        description: t("admin.mustHaveMerchant", "商店必须关联至少一个负责人，请在下方搜索并关联用户"),
        variant: "destructive",
      });
      setActiveSection("basic");
      return;
    }
    // Validate: shell store cannot have associated merchants (skip for landmark)
    if (template !== 'landmark' && isAdmin && storeLevel === 'shell' && associatedMerchants.length > 0) {
      toast({
        title: t("admin.cannotSave", "无法保存"),
        description: t("admin.shellCannotHaveMerchants", "空壳商店不可有关联用户，请先解除所有关联用户或切换商店身份"),
        variant: "destructive",
      });
      setActiveSection("basic");
      return;
    }

    setIsSubmitting(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("Not authenticated");

      const imageUrl = await uploadImage();
      const coverImageUrl = await uploadCoverImage();
      const ownerAvatarUrl = await uploadOwnerAvatar();
      const bannerUrl = await uploadBanner();
      

      const restaurantData = {
        name: data.name,
        name_en: data.name,
        name_pt: data.name,
        key_id: data.key_id || null,
        type: data.type,
        type_en: data.type,
        type_pt: data.type,
        description: data.description || null,
        description_en: data.description || null,
        description_pt: data.description || null,
        announcement_zh: data.announcement || null,
        announcement_en: data.announcement || null,
        announcement_pt: data.announcement || null,
        address: data.address,
        lat: data.lat,
        lng: data.lng,
        phone: data.phone || null,
        // website_url no longer managed from form
        official_website: data.official_website || null,
        takeaway_url: data.takeaway_url || null,
        
        visible: data.visible,
        show_takeaway_button: (template === 'landmark' || template === 'hotel') ? false : (storeLevel !== 'complete' ? false : data.show_takeaway_button),
        
        show_website_button: template === 'landmark' ? false : (template === 'hotel' ? data.show_website_button : (storeLevel !== 'complete' ? false : data.show_website_button)),
        show_ghost_intro: (template === 'ghost' || template === 'michelin') ? data.show_ghost_intro : true,
        
        image_url: imageUrl,
        cover_image_url: coverImageUrl,
        opening_hours: (template === 'ghost' || template === 'michelin') ? null : openingHours as any,
        template: isMichelinRestaurant ? 'michelin' : template,
        owner_avatar_url: ownerAvatarUrl,

        banner_url: bannerUrl,
        owner_bio: ownerBio || null,
        owner_bio_en: null,
        owner_bio_pt: null,
        owner_name: ownerName || null,
        owner_name_en: null,
        owner_name_pt: null,
        is_chain: template === 'landmark' ? false : isChain,
        brand_id: template === 'landmark' ? null : (isChain ? brandId : null),
        store_level: template === 'landmark' ? 'shell' : (isAdmin ? storeLevel : undefined),
        allow_merchant_edit_website: isAdmin ? (storeLevel !== 'complete' ? false : allowMerchantEditWebsite) : undefined,
        // Video fields for Ghost/Michelin template
        banner_media_type: (template === 'ghost' || template === 'michelin') ? bannerMediaType : 'image',
        promo_video_url: (template === 'ghost' || template === 'michelin') ? (promoVideoUrl || null) : null,
        promo_video_poster: (template === 'ghost' || template === 'michelin') ? (promoVideoPoster || null) : null,
        videos: (template === 'ghost' || template === 'michelin') ? (videos as any) : [],
        scenic_spots: template === 'landmark' ? (scenicSpots as any) : [],
        landmark_info: template === 'landmark' ? (landmarkInfo as any) : {},
      };

      if (restaurant) {
        const { error } = await supabase
          .from("restaurants")
          .update({ ...restaurantData, updated_by: user.id })
          .eq("id", restaurant.id);

        if (error) throw error;

        toast({
          title: t("common.success"),
          description: t("admin.restaurantUpdated"),
        });
      } else {
        const { data: insertedData, error } = await supabase
          .from("restaurants")
          .insert([{ ...restaurantData, created_by: user.id }])
          .select("id")
          .single();

        if (error) throw error;

        // Link associated merchants to the newly created restaurant
        if (insertedData && associatedMerchants.length > 0) {
          for (const m of associatedMerchants) {
            await supabase.from("merchant_restaurants").insert({
              user_id: m.user_id,
              restaurant_id: insertedData.id,
            });
            // Auto-upgrade role
            const { data: existingRole } = await supabase
              .from("user_roles")
              .select("role")
              .eq("user_id", m.user_id)
              .maybeSingle();
            if (!existingRole || existingRole.role === 'user') {
              if (existingRole) {
                await supabase.from("user_roles").update({ role: "merchant" }).eq("user_id", m.user_id);
              } else {
                await supabase.from("user_roles").insert({ user_id: m.user_id, role: "merchant" });
              }
            }
            const merchantType = storeLevel === 'basic' ? 'shallow' : null;
            await supabase.from("profiles").update({ merchant_type: merchantType }).eq("id", m.user_id);
          }
        }

        toast({
          title: t("common.success"),
          description: t("admin.restaurantCreated"),
        });
      }

      // Check for incomplete information and remind user
      const missingFields: string[] = [];
      if (!imageUrl) missingFields.push(template === 'landmark' ? t("admin.landmarkImage", "景点图片") : t("admin.restaurantImage", "餐厅图片"));
      if (template !== 'landmark' && !data.phone) missingFields.push(t("admin.phone", "电话"));
      if (!data.description) missingFields.push(template === 'landmark' ? t("admin.landmarkDescription", "景点概述") : t("admin.description", "描述"));
      if (template !== 'ghost' && template !== 'michelin' && template !== 'landmark') {
        const allClosed = DAYS.every(day => openingHours[day]?.closed);
        if (allClosed) missingFields.push(t("admin.openingHours", "营业时间"));
      }
      if (template !== 'landmark' && !data.official_website) missingFields.push(t("admin.officialWebsite", "官方网站"));

      if (missingFields.length > 0) {
        toast({
          title: t("admin.incompleteInfoReminder", "信息不完整提示"),
          description: t("admin.incompleteInfoDesc", "以下信息尚未填写，建议补充完整：") + missingFields.join("、"),
        });
      }

      if (!data.visible) {
        toast({
          title: t("admin.visibilityReminder", "温馨提示"),
          description: t("admin.visibilityReminderDesc", "当前前端显示为关闭状态，如果您希望其他人看到您的餐厅，请将前端显示打开"),
        });
      }

      queryClient.invalidateQueries({ queryKey: ["restaurants"] });
      queryClient.invalidateQueries({ queryKey: ["admin-restaurants"] });
      if (restaurant?.id) {
        queryClient.invalidateQueries({ queryKey: ["restaurant", restaurant.id] });
      }
      setOpen(false);
    } catch (error: any) {
      toast({
        title: t("common.error"),
        description: error.message,
        variant: "destructive",
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  const sections = [
    { id: "basic", icon: Store, label: t("admin.basicSettings", "基本设置") },
    { id: "content", icon: Globe, label: t("admin.contentInfo", "内容信息") },
    { id: "media", icon: ImageIcon, label: t("admin.mediaImages", "图片媒体") },
    { id: "location", icon: MapPin, label: t("admin.locationAndContact", "位置联系") },
    ...(template === 'default' ? [{ id: "hours", icon: Clock, label: t("admin.openingHours", "营业时间") }] : []),
    ...((template === 'ghost' || template === 'michelin') ? [{ id: "ghost", icon: ChefHat, label: t("admin.chefProfile", "大厨档案") }] : []),
    ...(template === 'landmark' ? [{ id: "landmark", icon: BookOpen, label: t("admin.ichingRegenerate", "易经卦象") }] : []),
  ];

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>{trigger}</DialogTrigger>
      <DialogContent className="max-w-[95vw] sm:max-w-6xl max-h-[95vh] overflow-hidden flex flex-col p-0">
        <DialogHeader className="px-6 pt-5 pb-3 border-b bg-muted/30">
          <div className="flex items-center justify-between pr-8">
            <DialogTitle className="text-xl flex items-center gap-2">
              <Store className="w-5 h-5 text-primary" />
              {restaurant ? t("admin.editRestaurant") : t("admin.addRestaurant")}
            </DialogTitle>
            {restaurant && template !== 'landmark' && (
              <Button
                type="button"
                variant="outline"
                size="sm"
                className="gap-1.5"
                onClick={() => {
                  setOpen(false);
                  navigateToEdit(`/restaurant/${restaurant.id}?edit=1`);
                }}
              >
                <FileText className="w-4 h-4" />
                {t("admin.freeEdit", "自由编辑")}
              </Button>
            )}
          </div>
          <DialogDescription className="text-sm">
            {restaurant ? t("admin.editRestaurantDetails") : t("admin.createRestaurantWithInfo")}
          </DialogDescription>
        </DialogHeader>

        {/* Mobile: Scrollable tab bar */}
        <div className="md:hidden border-b overflow-x-auto">
          <div className="flex gap-1 px-3 py-2 min-w-max">
            {sections.map((s) => (
              <Button
                key={s.id}
                type="button"
                variant={activeSection === s.id ? "default" : "ghost"}
                size="sm"
                className="gap-1.5 text-xs shrink-0"
                onClick={() => setActiveSection(s.id)}
              >
                <s.icon className="w-3.5 h-3.5" />
                {s.label}
              </Button>
            ))}
          </div>
        </div>

        <div className="flex flex-1 overflow-hidden">
          {/* Desktop: Left sidebar navigation */}
          <div className="hidden md:flex flex-col w-48 shrink-0 border-r bg-muted/20 py-2">
            {sections.map((s) => (
              <button
                key={s.id}
                type="button"
                onClick={() => setActiveSection(s.id)}
                className={cn(
                  "flex items-center gap-2.5 px-4 py-2.5 text-sm text-left transition-colors",
                  activeSection === s.id
                    ? "bg-primary/10 text-primary font-medium border-r-2 border-primary"
                    : "text-muted-foreground hover:text-foreground hover:bg-muted/50"
                )}
              >
                <s.icon className="w-4 h-4 shrink-0" />
                {s.label}
              </button>
            ))}
          </div>

          {/* Right: Content area */}
          <ScrollArea className="flex-1 h-[calc(95vh-200px)]">
            <form onSubmit={handleSubmit(onSubmit, showValidationErrors)} className="p-5 space-y-5">

              {/* ===== BASIC SETTINGS ===== */}
              {activeSection === "basic" && (
                <div className="space-y-5">
                  {/* Visibility Toggle */}
                  <Card className="border-primary/20 bg-gradient-to-br from-primary/5 to-background">
                    <CardContent className="p-4">
                      <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                          <div className="p-2 rounded-lg bg-primary/10">
                            <Globe className="w-5 h-5 text-primary" />
                          </div>
                          <div>
                            <Label className="text-base font-semibold">{t("admin.frontendDisplay")}</Label>
                            <p className="text-xs text-muted-foreground">{t("admin.frontendDisplayDesc")}</p>
                          </div>
                        </div>
                        <Switch
                          checked={visible}
                          onCheckedChange={(checked) => setValue("visible", checked)}
                        />
                      </div>
                    </CardContent>
                  </Card>

                  {/* Template Selection - hidden for landmark and hotel */}
                  {template !== 'landmark' && !isHotelRestaurant && (
                  <Card className="border-primary/20">
                    <CardContent className="p-5">
                      <Label className="text-base font-semibold flex items-center gap-2 mb-3">
                        <Store className="w-5 h-5 text-primary" />
                        {t("admin.restaurantTemplate")}
                      </Label>
                      {isMichelinRestaurant ? (
                        <div className="rounded-lg border border-primary/20 bg-primary/5 p-4">
                          <p className="text-sm font-medium text-foreground">{t("admin.templateMichelin", "米其林模板")}</p>
                          <p className="text-xs text-muted-foreground mt-1">{t("admin.michelinTemplateLocked", "米其林餐厅固定使用米其林模板，后台不可切换")}</p>
                        </div>
                      ) : (
                        <RadioGroup
                          value={template}
                          onValueChange={setTemplate}
                          className="grid grid-cols-1 md:grid-cols-2 gap-3"
                        >
                          <div className="flex items-start space-x-3 p-3 rounded-lg border border-border hover:border-primary/50 transition-colors cursor-pointer" onClick={() => setTemplate('default')}>
                            <RadioGroupItem value="default" id="template-default" className="mt-1" />
                            <div className="flex-1">
                              <Label htmlFor="template-default" className="text-sm font-medium cursor-pointer">
                                {t("admin.templateDefault")}
                              </Label>
                              <p className="text-xs text-muted-foreground mt-1">
                                {t("admin.templateDefaultDesc")}
                              </p>
                            </div>
                          </div>
                          <div className="flex items-start space-x-3 p-3 rounded-lg border border-border hover:border-primary/50 transition-colors cursor-pointer" onClick={() => setTemplate('ghost')}>
                            <RadioGroupItem value="ghost" id="template-ghost" className="mt-1" />
                            <div className="flex-1">
                              <Label htmlFor="template-ghost" className="text-sm font-medium cursor-pointer">
                                {t("admin.templateGhost", "大厨档案")}
                              </Label>
                              <p className="text-xs text-muted-foreground mt-1">
                                {t("admin.templateGhostDesc")}
                              </p>
                            </div>
                          </div>
                        </RadioGroup>
                      )}
                    </CardContent>
                  </Card>
                  )}

                  {/* Hotel badge - read-only indicator */}
                  {isHotelRestaurant && (
                    <Card className="border-primary/20 bg-primary/5">
                      <CardContent className="p-4 flex items-center gap-3">
                        <div className="p-2 rounded-lg bg-primary/10">
                          <Hotel className="w-5 h-5 text-primary" />
                        </div>
                        <div>
                          <p className="text-sm font-semibold text-foreground">{t("admin.templateHotel", "酒店模板")}</p>
                          <p className="text-xs text-muted-foreground">{t("admin.hotelTemplateFixed", "酒店专用模板，不可切换至其他模板")}</p>
                        </div>
                      </CardContent>
                    </Card>
                  )}

                  {/* Landmark badge - read-only indicator */}
                  {template === 'landmark' && (
                    <Card className="border-primary/20 bg-primary/5">
                      <CardContent className="p-4 flex items-center gap-3">
                        <div className="p-2 rounded-lg bg-primary/10">
                          <Building2 className="w-5 h-5 text-primary" />
                        </div>
                        <div>
                          <p className="text-sm font-semibold text-foreground">{t("admin.templateLandmark", "名胜古迹")}</p>
                          <p className="text-xs text-muted-foreground">{t("admin.landmarkTemplateFixed", "名胜古迹专用模板，无需选择")}</p>
                        </div>
                      </CardContent>
                    </Card>
                  )}

                  {/* Chain Restaurant & Brand - hidden for landmark and michelin */}
                  {template !== 'landmark' && !isMichelinRestaurant && (
                  <Card className="border-primary/20">
                    <CardContent className="p-5">
                      <Label className="text-base font-semibold flex items-center gap-2 mb-3">
                        <Building2 className="w-5 h-5 text-primary" />
                        {t("admin.restaurant.isChain")}
                      </Label>
                      <div className="space-y-4">
                        <div className="flex items-center justify-between p-3 border rounded-lg">
                          <div className="space-y-0.5">
                            <Label className="text-sm font-medium">{t("admin.restaurant.isChain")}</Label>
                            <p className="text-xs text-muted-foreground">{t("admin.restaurant.isChainDesc")}</p>
                          </div>
                          <Switch
                            checked={isChain}
                            onCheckedChange={(checked) => {
                              setIsChain(checked);
                              if (!checked) setBrandId(null);
                            }}
                          />
                        </div>
                        {isChain && brands && brands.length > 0 && (
                          <Select value={brandId || undefined} onValueChange={(val) => setBrandId(val || null)}>
                            <SelectTrigger>
                              <SelectValue placeholder={t("admin.restaurant.selectBrand")} />
                            </SelectTrigger>
                            <SelectContent>
                              {brands.filter((brand: Brand) => typeof brand.id === "string" && brand.id.trim().length > 0).map((brand: Brand) => (
                                <SelectItem key={brand.id} value={brand.id}>
                                  <span className="flex items-center gap-2">
                                    {brand.logo_url && (
                                      <img src={brand.logo_url} alt="" className="w-5 h-5 object-contain rounded" />
                                    )}
                                    {brand.name}
                                  </span>
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                        )}
                      </div>
                    </CardContent>
                  </Card>
                  )}

                  {/* Store Level & Display Settings - hidden for landmark */}
                  {template !== 'landmark' && (
                  <Card className="border-primary/20">
                    <CardContent className="p-5 space-y-4">
                      {isAdmin && (
                        <div className="space-y-2">
                          <Label className="text-sm font-medium flex items-center gap-2">
                            {t("admin.storeLevel", "商店身份")}
                          </Label>
                          <div className="grid grid-cols-3 gap-2">
                            {[
                              { value: 'complete', label: t("admin.storeLevelComplete", "完整商店"), color: 'border-green-500 bg-green-50 dark:bg-green-950' },
                              { value: 'basic', label: t("admin.storeLevelBasic", "基础商店"), color: 'border-blue-500 bg-blue-50 dark:bg-blue-950' },
                              { value: 'shell', label: t("admin.storeLevelShell", "空壳商店"), color: 'border-gray-400 bg-gray-50 dark:bg-gray-900' },
                            ].map(opt => (
                              <div
                                key={opt.value}
                                onClick={() => handleStoreLevelChange(opt.value)}
                                className={cn(
                                  "cursor-pointer rounded-lg border-2 p-2 text-center text-sm transition-all",
                                  storeLevel === opt.value ? opt.color : "border-muted"
                                )}
                              >
                                {opt.label}
                              </div>
                            ))}
                          </div>
                          <p className="text-xs text-muted-foreground">
                            {t("admin.storeLevelDesc", "基础/空壳商店无法使用外卖、订台、官网功能")}
                          </p>
                        </div>
                      )}

                      <div className="space-y-3">
                        <Label className="text-sm font-medium text-muted-foreground">
                          {t("admin.displaySettings")}
                        </Label>
                        <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
                          {(() => {
                            const isHotelTemplate = template === 'hotel';
                            const featuresDisabled = isHotelTemplate ? false : (isShallowMerchant || storeLevel !== 'complete');
                            return (
                              <>
                                {/* Hide takeaway/booking for hotel template */}
                                {!isHotelTemplate && (
                                <div className={`flex items-center space-x-2 p-3 rounded-lg border ${featuresDisabled ? 'bg-muted/50 opacity-60' : 'bg-muted/30'}`}>
                                  <Checkbox
                                    id="show_takeaway_button"
                                    checked={showTakeawayButton}
                                    disabled={featuresDisabled}
                                    onCheckedChange={(checked) => {
                                      if (featuresDisabled) {
                                        if (isShallowMerchant) handleShallowMerchantButtonRequest('takeaway');
                                        return;
                                      }
                                      setValue("show_takeaway_button", checked as boolean);
                                    }}
                                  />
                                  <Label htmlFor="show_takeaway_button" className={`text-sm flex items-center gap-2 ${featuresDisabled ? 'cursor-not-allowed' : 'cursor-pointer'}`}>
                                    <ShoppingBag className="w-4 h-4" />
                                    {t("admin.showTakeawayButton")}
                                  </Label>
                                </div>
                                )}
                                <div className={`flex items-center space-x-2 p-3 rounded-lg border ${featuresDisabled ? 'bg-muted/50 opacity-60' : 'bg-muted/30'}`}>
                                  <Checkbox
                                    id="show_website_button"
                                    checked={showWebsiteButton}
                                    disabled={featuresDisabled}
                                    onCheckedChange={(checked) => {
                                      if (featuresDisabled) {
                                        if (isShallowMerchant) handleShallowMerchantButtonRequest('website');
                                        return;
                                      }
                                      setValue("show_website_button", checked as boolean);
                                    }}
                                  />
                                  <Label htmlFor="show_website_button" className={`text-sm flex items-center gap-2 ${featuresDisabled ? 'cursor-not-allowed' : 'cursor-pointer'}`}>
                                    <WebIcon className="w-4 h-4" />
                                    {t("admin.showWebsiteButton", "显示官网按钮")}
                                  </Label>
                                </div>
                                {featuresDisabled && (
                                  <div className="col-span-2 md:col-span-3 flex items-center gap-2">
                                    <p className="text-xs text-muted-foreground">
                                      {storeLevel !== 'complete'
                                        ? t("admin.storeLevelFeatureNotice", "非完整商店无法开启外卖/订台/官网功能，需管理员升级商店身份")
                                        : t("admin.shallowMerchantButtonNotice", "浅层商家无法开启外卖/订台/官网按钮，如需开启请联系管理员")}
                                    </p>
                                    <a href="/membership" className="text-xs text-primary underline whitespace-nowrap hover:text-primary/80">
                                      {t("membership.learnMore", "了解会员")}
                                    </a>
                                  </div>
                                )}
                              </>
                            );
                          })()}
                          {isAdmin && (
                            <div className={`flex items-center space-x-2 p-3 rounded-lg border ${storeLevel !== 'complete' ? 'bg-muted/50 opacity-60' : 'bg-primary/5 border-primary/20'}`}>
                              <Checkbox
                                id="allow_merchant_edit_website"
                                checked={allowMerchantEditWebsite}
                                disabled={storeLevel !== 'complete'}
                                onCheckedChange={(checked) => {
                                  if (storeLevel !== 'complete') return;
                                  setAllowMerchantEditWebsite(checked as boolean);
                                }}
                              />
                              <Label htmlFor="allow_merchant_edit_website" className={`text-sm flex items-center gap-2 ${storeLevel !== 'complete' ? 'cursor-not-allowed' : 'cursor-pointer'}`}>
                                <WebIcon className="w-4 h-4" />
                                {t("admin.allowMerchantEditWebsite", "允许商家编辑链接")}
                              </Label>
                            </div>
                          )}
                        </div>
                      </div>

                      {template === 'ghost' && (
                        <div className="flex items-center space-x-2 p-3 rounded-lg border bg-muted/30">
                          <Checkbox
                            id="show_ghost_intro"
                            checked={showGhostIntro}
                            onCheckedChange={(checked) => setValue("show_ghost_intro", checked as boolean)}
                          />
                          <Label htmlFor="show_ghost_intro" className="cursor-pointer text-sm flex items-center gap-2">
                            <ChefHat className="w-4 h-4" />
                            {t("admin.showGhostIntro", "显示品牌介绍")}
                          </Label>
                        </div>
                      )}
                    </CardContent>
                  </Card>
                  )}

                  {/* Associated Merchants - hidden for landmark */}
                  {isAdmin && template !== 'landmark' && (
                    <Card className="border-primary/20">
                      <CardContent className="p-5 space-y-3">
                        <Label className="text-sm font-medium flex items-center gap-2">
                          <User className="w-4 h-4" />
                          {t("admin.associatedMerchants", "关联用户（负责人）")}
                          {(storeLevel === 'basic' || storeLevel === 'complete') && associatedMerchants.length === 0 && (
                            <span className="text-destructive text-xs">* {t("admin.required", "必填")}</span>
                          )}
                        </Label>
                        
                        {/* Current merchants */}
                        {associatedMerchants.length > 0 && (
                          <div className="space-y-2">
                            {associatedMerchants.map((m) => (
                              <div key={m.user_id} className="flex items-center gap-3 p-2.5 rounded-lg bg-primary/5 border border-primary/20">
                                <User className="w-4 h-4 text-primary" />
                                <div className="flex-1 min-w-0">
                                  <p className="text-sm font-medium truncate">{m.display_name}</p>
                                  <p className="text-xs text-muted-foreground truncate">{m.email}</p>
                                </div>
                                <Button
                                  type="button"
                                  variant="ghost"
                                  size="sm"
                                  className="h-7 px-2 text-destructive hover:text-destructive hover:bg-destructive/10"
                                  onClick={() => unassignMerchant(m.user_id)}
                                >
                                  <UserMinus className="w-3.5 h-3.5" />
                                </Button>
                              </div>
                            ))}
                          </div>
                        )}

                        {/* Search & assign */}
                        <div className="space-y-2">
                          <div className="relative">
                            <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                            <Input
                              placeholder={t("admin.searchMerchantPlaceholder", "搜索用户名以快捷关联...")}
                              className="pl-8 h-9 text-sm"
                              value={merchantSearchQuery}
                              onChange={(e) => {
                                setMerchantSearchQuery(e.target.value);
                                searchMerchants(e.target.value);
                              }}
                            />
                            {isSearchingMerchants && (
                              <Loader2 className="absolute right-2.5 top-1/2 -translate-y-1/2 w-4 h-4 animate-spin text-muted-foreground" />
                            )}
                          </div>
                          {merchantSearchResults.length > 0 && (
                            <div className="border rounded-lg divide-y max-h-40 overflow-y-auto">
                              {merchantSearchResults.map((r) => (
                                <div key={r.id} className="flex items-center gap-3 p-2 hover:bg-muted/50 transition-colors">
                                  <div className="flex-1 min-w-0">
                                    <p className="text-sm font-medium truncate">{r.display_name}</p>
                                    <p className="text-xs text-muted-foreground truncate">{r.email} · {r.role}</p>
                                  </div>
                                  <Button
                                    type="button"
                                    variant="outline"
                                    size="sm"
                                    className="h-7 px-2 gap-1 text-xs"
                                    onClick={() => assignMerchant(r.id)}
                                  >
                                    <UserPlus className="w-3.5 h-3.5" />
                                    {t("admin.linkUser", "关联")}
                                  </Button>
                                </div>
                              ))}
                            </div>
                          )}
                        </div>

                        {/* Warning for basic/complete without merchants */}
                        {(storeLevel === 'basic' || storeLevel === 'complete') && associatedMerchants.length === 0 && (
                          <p className="text-xs text-destructive font-medium">
                            ⚠️ {t("admin.storeMustHaveMerchant", `${storeLevel === 'basic' ? '基础' : '完整'}商店必须关联至少一个负责人`)}
                          </p>
                        )}
                        {storeLevel === 'shell' && associatedMerchants.length === 0 && (
                          <p className="text-xs text-muted-foreground">{t("admin.shellNoMerchantNeeded", "空壳商店无需关联用户")}</p>
                        )}
                      </CardContent>
                    </Card>
                   )}

                  {/* Visitor Info for Landmark - in basic settings */}
                  {template === 'landmark' && (
                    <Card className="border-primary/20">
                      <CardContent className="p-5">
                        <Label className="text-base font-semibold flex items-center gap-2 mb-4">
                          <Building2 className="w-5 h-5 text-primary" />
                          {t("admin.visitorInfo", "实用信息")}
                        </Label>
                        <LandmarkInfoEditor info={landmarkInfo} onChange={setLandmarkInfo} />
                      </CardContent>
                    </Card>
                  )}
                </div>
              )}

              {/* ===== CONTENT ===== */}
              {activeSection === "content" && (
                <div className="space-y-5">
                  <Card className="border-primary/20">
                    <CardContent className="p-5 space-y-5">
                      <div>
                        <Label className="text-base font-semibold flex items-center gap-2 mb-2">
                          <Globe className="w-5 h-5 text-primary" />
                          {template === 'landmark' ? t("admin.landmarkContent", "景点信息") : t("admin.contentInfo", "内容信息")}
                        </Label>
                        <p className="text-xs text-muted-foreground">
                          {template === 'landmark'
                            ? t("admin.landmarkContentHint", "填写景点名称和描述，描述将显示在景点概述卡片中")
                            : t("admin.contentEditHint", "现在按餐厅详情页的展示位置来编辑：先填顶部基础信息，再填顶部主叙事区，避免分不清对应位置。")}
                        </p>
                      </div>

                      {template !== 'landmark' && (
                        <div className="rounded-xl border border-border bg-muted/30 p-4 space-y-3">
                          <div>
                            <p className="text-sm font-semibold text-foreground">{t("admin.detailPageMapping", "详情页对应关系")}</p>
                            <p className="text-xs text-muted-foreground mt-1">{t("admin.detailPageMappingDesc", "你在这里改什么，前台详情页就改哪里。")}</p>
                          </div>
                          <div className="grid gap-3 md:grid-cols-3">
                            <div className="rounded-lg border border-border bg-background p-3">
                              <p className="text-sm font-medium">{t("admin.sectionBasicInfo", "① 顶部基础信息")}</p>
                              <p className="mt-1 text-xs text-muted-foreground">{t("admin.sectionBasicInfoDesc", "餐厅名、分类、简介：对应详情页顶部 Hero 的基础文案。")}</p>
                            </div>
                            <div className="rounded-lg border border-border bg-background p-3">
                              <p className="text-sm font-medium">{t("admin.sectionNarrative", "② 顶部主叙事区")}</p>
                              <p className="mt-1 text-xs text-muted-foreground">{t("admin.sectionNarrativeDesc", "顶部图片、标题、内容介绍、黄帝内经：对应详情页顶部主视觉与展开说明。")}</p>
                            </div>
                            <div className="rounded-lg border border-border bg-background p-3">
                              <p className="text-sm font-medium">{t("admin.sectionSystemGenerated", "③ 系统生成区")}</p>
                              <p className="mt-1 text-xs text-muted-foreground">{t("admin.sectionSystemGeneratedDesc", "I Ching / 易经内容：用于建筑叙事与解读内容，不是顶部主视觉区。")}</p>
                            </div>
                          </div>
                        </div>
                      )}

                      <div className="rounded-xl border border-border bg-background p-4 space-y-4">
                        <div>
                          <p className="text-sm font-semibold text-foreground">
                            {template === 'landmark' ? t("admin.landmarkBasicInfo", "景点基础信息") : t("admin.part1BasicInfo", "第一部分：顶部基础信息")}
                          </p>
                          <p className="mt-1 text-xs text-muted-foreground">
                            {template === 'landmark'
                              ? t("admin.landmarkBasicInfoDesc", "对应景点详情页顶部名称与概述。")
                              : t("admin.part1BasicInfoDesc", "对应详情页顶部 Hero 的基础文案区域。")}
                          </p>
                        </div>

                        <div className="space-y-2">
                          <Label htmlFor="name" className="text-sm font-medium">
                            {template === 'landmark' ? t("admin.landmarkName", "景点名称") : t("admin.restaurantName")}
                          </Label>
                          <Input id="name" {...register("name")} placeholder={template === 'landmark' ? t("admin.enterLandmarkName", "例如：桂林山水") : t("admin.enterRestaurantName")} className="text-base" />
                          {errors.name && <p className="text-sm text-destructive">{errors.name.message}</p>}
                        </div>

                        {template !== 'landmark' && (
                          <div className="space-y-3">
                            <div className="flex justify-between items-center">
                              <Label className="text-sm font-medium">{t("admin.restaurantType")}</Label>
                              {types.length < 3 && (
                                <Button type="button" variant="outline" size="sm" onClick={addType}>{t("admin.addType")}</Button>
                              )}
                            </div>
                            {types.map((type, index) => (
                              <div key={index} className="flex gap-2 items-center">
                                <TypeCombobox placeholder={t("admin.typeExample")} value={type} onChange={(value) => updateType(index, value)} suggestions={existingTypes?.uniqueZh || []} />
                                <Button type="button" variant="ghost" size="icon" onClick={() => removeType(index)} disabled={types.length === 1}><X className="h-4 w-4" /></Button>
                              </div>
                            ))}
                            {errors.type && <p className="text-sm text-destructive">{errors.type.message}</p>}
                          </div>
                        )}

                        <div className="space-y-2">
                          <Label htmlFor="description" className="text-sm font-medium">
                            {template === 'landmark' ? t("admin.landmarkDescription", "景点概述") : t("admin.description")}
                          </Label>
                          <RichTextEditor value={watch("description") || ""} onChange={(value) => setValue("description", value)} placeholder={template === 'landmark' ? t("admin.enterLandmarkDescription", "介绍景点的历史、特色和亮点...") : t("admin.enterDescription")} />
                        </div>

                        {template !== 'landmark' && (
                          <div className="space-y-2">
                            <Label htmlFor="announcement" className="text-sm font-medium">{t("admin.announcement")}</Label>
                            <Textarea id="announcement" {...register("announcement")} rows={2} placeholder={t("admin.enterAnnouncement")} />
                            <p className="text-xs text-muted-foreground">{t("admin.announcementNotNarrative", "这部分是补充提示，不属于顶部主叙事图片区。")}</p>
                          </div>
                        )}
                      </div>

                      {restaurant?.id && (template === 'ghost' || template === 'michelin') && (
                        <div className="rounded-xl border border-border bg-background p-4">
                          <div className="mb-4">
                            <p className="text-sm font-semibold text-foreground">{t("admin.part2Narrative", "第二部分：顶部主叙事区")}</p>
                            <p className="mt-1 text-xs text-muted-foreground">{t("admin.part2NarrativeDesc", "对应详情页顶部大图、主标题、内容介绍，以及展开后看到的《黄帝内经》解读。")}</p>
                          </div>
                          <ChefRecommendedDishesEditor restaurantId={restaurant.id} mode="featured" />
                        </div>
                      )}

                      {restaurant?.id && template !== 'landmark' && (
                        <div className="rounded-xl border border-border bg-background p-4">
                          <div className="mb-4">
                            <p className="text-sm font-semibold text-foreground">{t("admin.part3IChing", "第三部分：易经 / 解读生成")}</p>
                            <p className="mt-1 text-xs text-muted-foreground">{t("admin.part3IChingDesc", "这部分服务于详情页叙事与解读模块，和上面的顶部主叙事区是分开的。")}</p>
                          </div>
                          <IChingRegenerateSection
                            restaurantId={restaurant.id}
                            restaurantName={watch("name") || restaurant?.name || ""}
                          />
                        </div>
                      )}
                    </CardContent>
                  </Card>
                </div>
              )}

              {/* ===== MEDIA / IMAGES ===== */}
              {activeSection === "media" && (
                <div className="space-y-5">
                  {/* Restaurant & Cover Images */}
                  <Card className="border-primary/20">
                    <CardContent className="p-5">
                      <Label className="text-base font-semibold flex items-center gap-2 mb-3">
                        <Upload className="w-5 h-5 text-primary" />
                        {t("admin.restaurantImages")}
                      </Label>
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        {/* Main Image */}
                        <div className="space-y-3">
                          <Label className="text-sm font-medium">{t("admin.mainImage", "主图")}</Label>
                          <div className="flex items-start gap-3">
                            {imagePreview && (
                              <div className="relative group">
                                <img src={imagePreview} alt="Preview" className="w-28 h-28 object-cover rounded-lg shadow ring-2 ring-primary/20 group-hover:scale-105 transition-transform" />
                                <Button type="button" variant="destructive" size="icon" className="absolute -top-2 -right-2 h-6 w-6 shadow-lg opacity-0 group-hover:opacity-100 transition-opacity rounded-full" onClick={() => { setImageFile(null); setImagePreview(null); }}><X className="h-3 w-3" /></Button>
                              </div>
                            )}
                            <Label htmlFor="image-upload" className="cursor-pointer">
                              <div className="flex flex-col items-center gap-2 px-5 py-3 border-2 border-dashed border-primary/30 rounded-lg hover:border-primary hover:bg-primary/5 transition-all">
                                <Upload className="h-5 w-5 text-primary" />
                                <p className="font-medium text-xs">{t("admin.uploadImage")}</p>
                              </div>
                              <Input id="image-upload" type="file" accept="image/*" className="hidden" onChange={handleImageChange} />
                            </Label>
                          </div>
                        </div>

                        {/* Cover Image - only for default template */}
                        {template !== 'ghost' && (
                          <div className="space-y-3">
                            <Label className="text-sm font-medium">{t("admin.coverImage", "封面图")}</Label>
                            <div className="flex items-start gap-3">
                              {coverImagePreview && (
                                <div className="relative group">
                                  <img src={coverImagePreview} alt="Cover Preview" className="w-28 h-28 object-cover rounded-lg shadow ring-2 ring-primary/20 group-hover:scale-105 transition-transform" />
                                  <Button type="button" variant="destructive" size="icon" className="absolute -top-2 -right-2 h-6 w-6 shadow-lg opacity-0 group-hover:opacity-100 transition-opacity rounded-full" onClick={() => { setCoverImageFile(null); setCoverImagePreview(null); }}><X className="h-3 w-3" /></Button>
                                </div>
                              )}
                              <Label htmlFor="cover-image-upload" className="cursor-pointer">
                                <div className="flex flex-col items-center gap-2 px-5 py-3 border-2 border-dashed border-accent/30 rounded-lg hover:border-accent hover:bg-accent/5 transition-all">
                                  <ImageIcon className="h-5 w-5 text-accent" />
                                  <p className="font-medium text-xs">{t("admin.uploadImage")}</p>
                                </div>
                                <Input id="cover-image-upload" type="file" accept="image/*" className="hidden" onChange={handleCoverImageChange} />
                              </Label>
                            </div>
                          </div>
                        )}
                      </div>
                    </CardContent>
                  </Card>

                  {/* Dish/Scenic Images Gallery */}
                  {restaurant?.id && (
                    <Card className="border-primary/20">
                      <CardContent className="p-5">
                        <Label className="text-base font-semibold flex items-center gap-2 mb-3">
                          <ImageIcon className="w-5 h-5 text-primary" />
                          {template === 'landmark' ? t("admin.scenicGallery", "景点图库") : t("admin.dishGallery")}
                        </Label>
                        {template === 'landmark' && (
                          <p className="text-xs text-muted-foreground mb-3">{t("admin.scenicGalleryHint", "上传代表性景点照片，将在景点详情页以图库形式展示")}</p>
                        )}
                        <DishImageManager restaurantId={restaurant.id} />
                      </CardContent>
                    </Card>
                  )}


                  {/* Ghost: Visual Assets */}
                  {template === 'ghost' && (
                    <Card className="border-primary/20">
                      <CardContent className="p-5">
                        <Label className="text-base font-semibold flex items-center gap-2 mb-3">
                          <Film className="w-5 h-5 text-primary" />
                          {t("admin.visualAssets", "视觉素材")}
                        </Label>
                        
                        <div className="mb-5">
                          <RestaurantVideoManager
                            bannerMediaType={bannerMediaType}
                            onBannerMediaTypeChange={setBannerMediaType}
                            promoVideoUrl={promoVideoUrl}
                            onPromoVideoUrlChange={setPromoVideoUrl}
                            promoVideoPoster={promoVideoPoster}
                            onPromoVideoPosterChange={setPromoVideoPoster}
                            videos={videos}
                            onVideosChange={setVideos}
                          />
                        </div>
                        
                        {bannerMediaType === 'image' && (
                          <div className="space-y-3 p-4 border rounded-lg bg-muted/20 mb-5">
                            <div className="flex items-center gap-2">
                              <ImageIcon className="w-4 h-4 text-primary" />
                              <span className="text-sm font-medium">{t("admin.backgroundImage", "背景图")}</span>
                            </div>
                            <p className="text-xs text-muted-foreground">{t("admin.backgroundImageDesc", "此图片将显示在详情页顶部作为背景横幅")}</p>
                            <div className="flex items-start gap-4">
                              {bannerPreview && (
                                <div className="relative group">
                                  <img src={bannerPreview} alt="Banner Preview" className="w-40 h-20 object-cover rounded-lg shadow ring-2 ring-primary/20 group-hover:scale-105 transition-transform" />
                                  <Button type="button" variant="destructive" size="icon" className="absolute -top-2 -right-2 h-6 w-6 shadow-lg opacity-0 group-hover:opacity-100 transition-opacity rounded-full" onClick={() => { setBannerFile(null); setBannerPreview(null); }}><X className="h-3 w-3" /></Button>
                                </div>
                              )}
                              <Label htmlFor="ghost-banner-upload" className="cursor-pointer">
                                <div className="flex flex-col items-center gap-2 px-5 py-3 border-2 border-dashed border-primary/30 rounded-lg hover:border-primary hover:bg-primary/5 transition-all">
                                  <ImageIcon className="h-5 w-5 text-primary" />
                                  <p className="font-medium text-xs">{t("admin.uploadImage")}</p>
                                  <p className="text-xs text-muted-foreground">16:9 {t("admin.recommended", "推荐")}</p>
                                </div>
                                <Input id="ghost-banner-upload" type="file" accept="image/*" className="hidden" onChange={handleBannerChange} />
                              </Label>
                            </div>
                          </div>
                        )}

                        {/* Signature Dish */}
                        <div className="space-y-3 p-4 border rounded-lg bg-muted/20">
                          <div className="flex items-center gap-2">
                            <UtensilsCrossed className="w-4 h-4 text-primary" />
                            <span className="text-sm font-medium">{t("admin.signatureDish", "招牌美食")}</span>
                          </div>
                          <p className="text-xs text-muted-foreground">{t("admin.signatureDishDesc", "此图片将显示在详情页美食展示区")}</p>
                          <div className="flex items-start gap-4">
                            {coverImagePreview && (
                              <div className="relative group">
                                <img src={coverImagePreview} alt="Food Image Preview" className="w-32 h-32 object-cover rounded-lg shadow ring-2 ring-primary/20 group-hover:scale-105 transition-transform" />
                                <Button type="button" variant="destructive" size="icon" className="absolute -top-2 -right-2 h-6 w-6 shadow-lg opacity-0 group-hover:opacity-100 transition-opacity rounded-full" onClick={() => { setCoverImageFile(null); setCoverImagePreview(null); }}><X className="h-3 w-3" /></Button>
                              </div>
                            )}
                            <Label htmlFor="ghost-cover-image-upload" className="cursor-pointer">
                              <div className="flex flex-col items-center gap-2 px-5 py-3 border-2 border-dashed border-primary/30 rounded-lg hover:border-primary hover:bg-primary/5 transition-all">
                                <UtensilsCrossed className="h-5 w-5 text-primary" />
                                <p className="font-medium text-xs">{t("admin.uploadImage")}</p>
                                <p className="text-xs text-muted-foreground">1:1 {t("admin.recommended", "推荐")}</p>
                              </div>
                              <Input id="ghost-cover-image-upload" type="file" accept="image/*" className="hidden" onChange={handleCoverImageChange} />
                            </Label>
                          </div>
                        </div>
                      </CardContent>
                    </Card>
                   )}

                  {/* Landmark: Scenic Spots */}
                  {template === 'landmark' && (
                    <Card className="border-primary/20">
                      <CardContent className="p-5">
                        <LandmarkSpotsEditor spots={scenicSpots} onChange={setScenicSpots} />
                      </CardContent>
                    </Card>
                  )}
                </div>
              )}

              {/* ===== LOCATION & CONTACT ===== */}
              {activeSection === "location" && (
                <div className="space-y-5">
                  <Card className="border-primary/20">
                    <CardContent className="p-5 space-y-4">
                      <Label className="text-base font-semibold flex items-center gap-2">
                        <MapPin className="w-5 h-5 text-primary" />
                        {t("admin.locationAndContact")}
                      </Label>
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className="space-y-2">
                          <Label htmlFor="address" className="text-sm font-medium flex items-center gap-2">
                            <MapPin className="w-4 h-4" />
                            {t("admin.address")}
                          </Label>
                          <Input id="address" {...register("address")} placeholder={t("admin.enterAddress")} />
                          {errors.address && <p className="text-sm text-destructive">{errors.address.message}</p>}
                        </div>
                        <div className="space-y-2">
                          <Label htmlFor="phone" className="text-sm font-medium flex items-center gap-2">
                            <Phone className="w-4 h-4" />
                            {t("admin.phone")}
                          </Label>
                          <Input id="phone" {...register("phone")} placeholder="+351..." />
                        </div>
                      </div>
                      {isAdmin && (
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                          <div className="space-y-2">
                            <Label htmlFor="key_id" className="text-sm font-medium flex items-center gap-2">
                              <Key className="w-4 h-4" />
                              Key ID (API)
                            </Label>
                            <Input id="key_id" {...register("key_id")} placeholder={t("admin.keyIdPlaceholder", "例如: saldanha01")} />
                          </div>
                        </div>
                      )}
                    </CardContent>
                  </Card>

                  {/* Links */}
                  <Card className="border-primary/20">
                    <CardContent className="p-5 space-y-4">
                      <Label className="text-base font-semibold flex items-center gap-2">
                        <Link className="w-5 h-5 text-primary" />
                        {t("admin.links", "链接管理")}
                      </Label>
                      <div className="space-y-2">
                        <Label htmlFor="official_website" className="text-sm font-medium flex items-center gap-2">
                          <Globe className="w-4 h-4" />
                          {t("admin.officialWebsite", "官网链接")}
                        </Label>
                        <Input id="official_website" {...register("official_website")} placeholder="https://www.example.com" disabled={!isAdmin && !allowMerchantEditWebsite} className={(!isAdmin && !allowMerchantEditWebsite) ? "bg-muted cursor-not-allowed" : ""} />
                        {!isAdmin && !allowMerchantEditWebsite && (
                          <p className="text-xs text-muted-foreground">{t("admin.officialWebsiteDisabled", "需要管理员开启编辑权限")}</p>
                        )}
                      </div>
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className="space-y-2">
                          <Label htmlFor="takeaway_url" className="text-sm font-medium flex items-center gap-2">
                            <ShoppingBag className="w-4 h-4" />
                            {t("admin.takeawayUrl", "外卖链接")}
                          </Label>
                          <Input id="takeaway_url" {...register("takeaway_url")} placeholder="https://takeaway.example.com" disabled={!isAdmin && !allowMerchantEditWebsite} className={(!isAdmin && !allowMerchantEditWebsite) ? "bg-muted cursor-not-allowed" : ""} />
                          <p className="text-xs text-muted-foreground">{t("admin.takeawayUrlHint", "用户点击外卖按钮时跳转的链接")}</p>
                        </div>
                      </div>
                    </CardContent>
                  </Card>

                  {/* Map */}
                  <Card className="border-primary/20">
                    <CardContent className="p-5 space-y-4">
                      <Label className="text-base font-semibold flex items-center gap-2">
                        <MapPin className="w-5 h-5 text-primary" />
                        {t("admin.location")}
                      </Label>
                      {/* Geocoding search */}
                      <div className="flex gap-2">
                        <Input 
                          placeholder={t("admin.searchAddressPlaceholder", "输入地址搜索经纬度...")}
                          defaultValue={watch("address") || ""}
                          id="geocode-input"
                          onKeyDown={(e) => {
                            if (e.key === 'Enter') {
                              e.preventDefault();
                              const input = document.getElementById('geocode-input') as HTMLInputElement;
                              if (input?.value) handleGeocode(input.value);
                            }
                          }}
                        />
                        <Button 
                          type="button" 
                          variant="outline" 
                          size="sm"
                          disabled={isGeocoding}
                          onClick={() => {
                            const input = document.getElementById('geocode-input') as HTMLInputElement;
                            if (input?.value) handleGeocode(input.value);
                          }}
                        >
                          {isGeocoding ? <Loader2 className="w-4 h-4 animate-spin" /> : <Search className="w-4 h-4" />}
                        </Button>
                      </div>
                      <div className="grid grid-cols-2 gap-4 mb-2">
                        <div className="space-y-2">
                          <Label htmlFor="lat" className="text-sm font-medium">{t("admin.latitude")}</Label>
                          <Input id="lat" type="number" step="any" {...register("lat", { valueAsNumber: true })} />
                        </div>
                        <div className="space-y-2">
                          <Label htmlFor="lng" className="text-sm font-medium">{t("admin.longitude")}</Label>
                          <Input id="lng" type="number" step="any" {...register("lng", { valueAsNumber: true })} />
                        </div>
                      </div>
                      {template !== 'ghost' && (
                        <>
                          <div ref={mapContainer} className="h-80 w-full rounded-lg border-2 border-primary/20 shadow-sm" style={{ minHeight: '320px' }} />
                          <p className="text-sm text-muted-foreground flex items-center gap-2">
                            <MapPin className="w-4 h-4" />
                            {t("admin.clickOrDragToSetLocation")}
                          </p>
                        </>
                      )}
                    </CardContent>
                  </Card>
                </div>
              )}

              {/* ===== OPENING HOURS ===== */}
              {activeSection === "hours" && template !== 'ghost' && (
                <div className="space-y-5">
                  <Card className="border-primary/20 overflow-hidden">
                    <CardContent className="p-3 md:p-5 space-y-4">
                      <Label className="text-base font-semibold flex items-center gap-2">
                        <Clock className="w-5 h-5 text-primary" />
                        {t("admin.openingHours")}
                      </Label>
                      <div className="space-y-2">
                        {DAYS.map((day) => (
                          <div key={day} className="space-y-2 p-2 md:p-3 rounded-lg hover:bg-muted/50 transition-colors">
                            {/* Mobile Layout */}
                            <div className="md:hidden space-y-2">
                              <div className="flex items-center justify-between">
                                <Label className="capitalize font-semibold text-sm">{t(`admin.day.${day}`)}</Label>
                                <div className="flex items-center gap-2">
                                  <div className="flex items-center gap-1">
                                    <Checkbox id={`split-mobile-${day}`} checked={openingHours[day].splitShift} onCheckedChange={(checked) => setOpeningHours({ ...openingHours, [day]: { ...openingHours[day], splitShift: checked as boolean } })} disabled={openingHours[day].closed} className="h-4 w-4" />
                                    <Label htmlFor={`split-mobile-${day}`} className="cursor-pointer text-xs">{t("admin.splitShiftShort", "分段")}</Label>
                                  </div>
                                  <div className="flex items-center gap-1">
                                    <Checkbox id={`closed-mobile-${day}`} checked={openingHours[day].closed} onCheckedChange={(checked) => setOpeningHours({ ...openingHours, [day]: { ...openingHours[day], closed: checked as boolean } })} className="h-4 w-4" />
                                    <Label htmlFor={`closed-mobile-${day}`} className="cursor-pointer text-xs">{t("admin.closed")}</Label>
                                  </div>
                                </div>
                              </div>
                              {!openingHours[day].closed && (
                                <div className="space-y-1.5">
                                  {openingHours[day].splitShift ? (
                                    <div className="space-y-1.5">
                                      <div className="grid grid-cols-[32px_1fr_12px_1fr] gap-1 items-center">
                                        <span className="text-xs text-muted-foreground">{t("admin.lunch", "午餐")}</span>
                                        <Input type="time" value={openingHours[day].open} onChange={(e) => setOpeningHours({ ...openingHours, [day]: { ...openingHours[day], open: e.target.value } })} className="h-8 text-xs px-2 min-w-0" />
                                        <span className="text-muted-foreground text-xs text-center">-</span>
                                        <Input type="time" value={openingHours[day].close} onChange={(e) => setOpeningHours({ ...openingHours, [day]: { ...openingHours[day], close: e.target.value } })} className="h-8 text-xs px-2 min-w-0" />
                                      </div>
                                      <div className="grid grid-cols-[32px_1fr_12px_1fr] gap-1 items-center">
                                        <span className="text-xs text-muted-foreground">{t("admin.dinner", "晚餐")}</span>
                                        <Input type="time" value={openingHours[day].open2 || "19:00"} onChange={(e) => setOpeningHours({ ...openingHours, [day]: { ...openingHours[day], open2: e.target.value } })} className="h-8 text-xs px-2 min-w-0" />
                                        <span className="text-muted-foreground text-xs text-center">-</span>
                                        <Input type="time" value={openingHours[day].close2 || "23:00"} onChange={(e) => setOpeningHours({ ...openingHours, [day]: { ...openingHours[day], close2: e.target.value } })} className="h-8 text-xs px-2 min-w-0" />
                                      </div>
                                    </div>
                                  ) : (
                                    <div className="grid grid-cols-[1fr_12px_1fr] gap-1 items-center">
                                      <Input type="time" value={openingHours[day].open} onChange={(e) => setOpeningHours({ ...openingHours, [day]: { ...openingHours[day], open: e.target.value } })} className="h-8 text-xs px-2 min-w-0" />
                                      <span className="text-muted-foreground text-xs text-center">-</span>
                                      <Input type="time" value={openingHours[day].close} onChange={(e) => setOpeningHours({ ...openingHours, [day]: { ...openingHours[day], close: e.target.value } })} className="h-8 text-xs px-2 min-w-0" />
                                    </div>
                                  )}
                                </div>
                              )}
                            </div>
                            {/* Desktop Layout */}
                            <div className="hidden md:block">
                              <div className="grid grid-cols-[120px_1fr_auto] gap-4 items-center">
                                <Label className="capitalize font-semibold">{t(`admin.day.${day}`)}</Label>
                                <div className="flex items-center gap-2">
                                  <Checkbox id={`split-${day}`} checked={openingHours[day].splitShift} onCheckedChange={(checked) => setOpeningHours({ ...openingHours, [day]: { ...openingHours[day], splitShift: checked as boolean } })} disabled={openingHours[day].closed} />
                                  <Label htmlFor={`split-${day}`} className="cursor-pointer text-sm">{t("admin.splitShift", "分段营业")}</Label>
                                </div>
                                <div className="flex items-center space-x-2">
                                  <Checkbox id={`closed-${day}`} checked={openingHours[day].closed} onCheckedChange={(checked) => setOpeningHours({ ...openingHours, [day]: { ...openingHours[day], closed: checked as boolean } })} />
                                  <Label htmlFor={`closed-${day}`} className="cursor-pointer">{t("admin.closed")}</Label>
                                </div>
                              </div>
                              {!openingHours[day].closed && (
                                <div className="ml-[120px] space-y-2 mt-2">
                                  {openingHours[day].splitShift ? (
                                    <div className="space-y-2">
                                      <div className="flex items-center gap-2">
                                        <span className="text-sm text-muted-foreground w-12">{t("admin.lunch", "午餐")}</span>
                                        <Input type="time" value={openingHours[day].open} onChange={(e) => setOpeningHours({ ...openingHours, [day]: { ...openingHours[day], open: e.target.value } })} className="w-32" />
                                        <span className="text-muted-foreground">-</span>
                                        <Input type="time" value={openingHours[day].close} onChange={(e) => setOpeningHours({ ...openingHours, [day]: { ...openingHours[day], close: e.target.value } })} className="w-32" />
                                      </div>
                                      <div className="flex items-center gap-2">
                                        <span className="text-sm text-muted-foreground w-12">{t("admin.dinner", "晚餐")}</span>
                                        <Input type="time" value={openingHours[day].open2 || "19:00"} onChange={(e) => setOpeningHours({ ...openingHours, [day]: { ...openingHours[day], open2: e.target.value } })} className="w-32" />
                                        <span className="text-muted-foreground">-</span>
                                        <Input type="time" value={openingHours[day].close2 || "23:00"} onChange={(e) => setOpeningHours({ ...openingHours, [day]: { ...openingHours[day], close2: e.target.value } })} className="w-32" />
                                      </div>
                                    </div>
                                  ) : (
                                    <div className="flex items-center gap-2">
                                      <Input type="time" value={openingHours[day].open} onChange={(e) => setOpeningHours({ ...openingHours, [day]: { ...openingHours[day], open: e.target.value } })} className="w-32" />
                                      <span className="text-muted-foreground">-</span>
                                      <Input type="time" value={openingHours[day].close} onChange={(e) => setOpeningHours({ ...openingHours, [day]: { ...openingHours[day], close: e.target.value } })} className="w-32" />
                                    </div>
                                  )}
                                </div>
                              )}
                            </div>
                          </div>
                        ))}
                      </div>
                    </CardContent>
                  </Card>
                </div>
              )}

              {/* ===== GHOST SPECIAL: Chef Profile ===== */}
              {activeSection === "ghost" && (template === 'ghost' || template === 'michelin') && (
                <div className="space-y-5">
                  <Card className="border-primary/20">
                    <CardContent className="p-5">
                      <Label className="text-base font-semibold flex items-center gap-2 mb-3">
                        <ChefHat className="w-5 h-5 text-primary" />
                        {t("admin.chefProfile", "大厨档案")}
                      </Label>
                      
                      {/* Owner Name */}
                      <div className="space-y-3 mb-5">
                        <Label className="text-sm font-medium">{t("admin.chefName", "大厨名称")}</Label>
                        <Input value={ownerName} onChange={(e) => setOwnerName(e.target.value)} placeholder={t("admin.chefNamePlaceholder", "输入大厨名称")} />
                      </div>

                      {/* Owner Avatar */}
                      <div className="space-y-3 mb-5">
                        <span className="text-sm font-medium">{t("admin.ownerAvatar")}</span>
                        <div className="flex items-center gap-4">
                          {ownerAvatarPreview && (
                            <div className="relative group">
                              <img src={ownerAvatarPreview} alt="Owner Avatar" className="w-20 h-20 object-cover rounded-full shadow ring-2 ring-primary/20 group-hover:scale-105 transition-transform" />
                              <Button type="button" variant="destructive" size="icon" className="absolute -top-2 -right-2 h-6 w-6 shadow-lg opacity-0 group-hover:opacity-100 transition-opacity rounded-full" onClick={() => { setOwnerAvatarFile(null); setOwnerAvatarPreview(null); }}><X className="h-3 w-3" /></Button>
                            </div>
                          )}
                          <Label htmlFor="owner-avatar-upload" className="cursor-pointer">
                            <div className="flex flex-col items-center gap-2 px-5 py-3 border-2 border-dashed border-primary/30 rounded-lg hover:border-primary hover:bg-primary/5 transition-all">
                              <User className="h-5 w-5 text-primary" />
                              <p className="font-medium text-xs">{t("admin.uploadImage")}</p>
                            </div>
                            <Input id="owner-avatar-upload" type="file" accept="image/*" className="hidden" onChange={handleOwnerAvatarChange} />
                          </Label>
                        </div>
                      </div>
                      
                      {/* Owner Bio */}
                      <div className="space-y-3 mb-5">
                        <Label className="text-sm font-medium">{t("admin.ownerStory", "主理人故事")}</Label>
                        <Textarea value={ownerBio} onChange={(e) => setOwnerBio(e.target.value)} rows={6} placeholder={t("admin.ownerStoryPlaceholder", "只需填写一种语言，其余语言会自动翻译")} />
                      </div>

                      {restaurant?.id && <ChefRecommendedDishesEditor restaurantId={restaurant.id} mode="signature" />}

                    </CardContent>
                  </Card>
                </div>
              )}

              {/* ===== I CHING (Landmark) ===== */}
              {activeSection === "landmark" && template === 'landmark' && (
                <div className="space-y-5">
                  {/* I Ching */}
                  {restaurant?.id && (
                    <IChingRegenerateSection restaurantId={restaurant.id} restaurantName={restaurant.name || ""} />
                  )}
                  {!restaurant?.id && (
                    <Card className="border-amber-500/30 bg-amber-50/5">
                      <CardContent className="p-5">
                        <p className="text-sm text-muted-foreground">{t("admin.saveFirstForIChing", "请先保存景点后再管理易经卦象")}</p>
                      </CardContent>
                    </Card>
                  )}
                </div>
              )}

            </form>
          </ScrollArea>
        </div>

        <div className="flex items-center justify-between px-5 py-3 border-t bg-muted/30">
          <div className="flex items-center gap-1">
            {sections.map((s, i) => (
              <div
                key={s.id}
                className={cn(
                  "w-2 h-2 rounded-full transition-colors cursor-pointer",
                  activeSection === s.id ? "bg-primary" : "bg-muted-foreground/30"
                )}
                onClick={() => setActiveSection(s.id)}
              />
            ))}
          </div>
          <div className="flex gap-2">
            <Button type="button" variant="outline" size="sm" onClick={() => setOpen(false)}>
              {t("common.cancel")}
            </Button>
            <Button type="submit" size="sm" disabled={isSubmitting} onClick={handleSubmit(onSubmit)} className="gap-2">
              <Store className="w-4 h-4" />
              {isSubmitting ? t("common.saving") : t("common.save")}
            </Button>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}
