import { useTranslation } from "react-i18next";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";

export interface LandmarkInfo {
  subtitle?: string;
  subtitle_lang?: string;
  subtitleZh?: string;
  subtitleEn?: string;
  subtitlePt?: string;
  bestSeason?: string;
  bestSeason_lang?: string;
  bestSeasonZh?: string;
  bestSeasonEn?: string;
  bestSeasonPt?: string;
  duration?: string;
  duration_lang?: string;
  durationZh?: string;
  durationEn?: string;
  durationPt?: string;
  altitude?: string;
  geology?: string;
  geology_lang?: string;
  geologyZh?: string;
  geologyEn?: string;
  geologyPt?: string;
  ticket?: string;
  ticket_lang?: string;
  transport?: string;
  transport_lang?: string;
  tips?: string;
  tips_lang?: string;
  openingHoursInfo?: string;
  openingHoursInfo_lang?: string;
}

interface LandmarkInfoEditorProps {
  info: LandmarkInfo;
  onChange: (info: LandmarkInfo) => void;
}

export function LandmarkInfoEditor({ info, onChange }: LandmarkInfoEditorProps) {
  const { t } = useTranslation();

  // Single input updates the unified field (and syncs to legacy tri-lingual fields for backward compat)
  const updateField = (base: string, value: string) => {
    onChange({
      ...info,
      [base]: value,
      // Legacy backward compat
      [`${base}Zh`]: value,
      [`${base}En`]: value,
      [`${base}Pt`]: value,
    });
  };

  const update = (field: keyof LandmarkInfo, value: string) => {
    onChange({ ...info, [field]: value });
  };

  const getVal = (base: string) => {
    return (info as any)[base] || (info as any)[`${base}Zh`] || (info as any)[`${base}En`] || "";
  };

  return (
    <div className="space-y-4">
      {/* Subtitle */}
      <div className="space-y-2">
        <Label className="text-sm font-medium">{t("admin.landmarkSubtitle", "景点副标题")}</Label>
        <p className="text-xs text-muted-foreground">显示在景点概述卡片中的副标题</p>
        <Input
          value={getVal("subtitle")}
          onChange={(e) => updateField("subtitle", e.target.value)}
          placeholder="世界自然遗产 · 喀斯特地貌 / World Natural Heritage"
          className="h-8 text-sm"
        />
      </div>

      {/* Visitor Info Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {/* Best Season */}
        <div className="space-y-2">
          <Label className="text-sm font-medium">{t("admin.bestSeason", "最佳季节")}</Label>
          <Input
            value={getVal("bestSeason")}
            onChange={(e) => updateField("bestSeason", e.target.value)}
            placeholder="4月-10月 / Apr - Oct"
            className="h-8 text-sm"
          />
        </div>

        {/* Duration */}
        <div className="space-y-2">
          <Label className="text-sm font-medium">{t("admin.visitDuration", "建议游览时间")}</Label>
          <Input
            value={getVal("duration")}
            onChange={(e) => updateField("duration", e.target.value)}
            placeholder="2-4天 / 2-4 days"
            className="h-8 text-sm"
          />
        </div>

        {/* Altitude */}
        <div className="space-y-2">
          <Label className="text-sm font-medium">{t("admin.altitude", "海拔")}</Label>
          <Input value={info.altitude || ""} onChange={(e) => update("altitude", e.target.value)} placeholder="150-1,100m" className="h-8 text-sm" />
        </div>

        {/* Geology */}
        <div className="space-y-2">
          <Label className="text-sm font-medium">{t("admin.geology", "地貌类型")}</Label>
          <Input
            value={getVal("geology")}
            onChange={(e) => updateField("geology", e.target.value)}
            placeholder="喀斯特 / Karst"
            className="h-8 text-sm"
          />
        </div>

        {/* Ticket */}
        <div className="space-y-2">
          <Label className="text-sm font-medium">{t("landmark.tickets", "门票信息")}</Label>
          <Input
            value={info.ticket || ""}
            onChange={(e) => update("ticket", e.target.value)}
            placeholder="¥50 / 免费 / Free"
            className="h-8 text-sm"
          />
        </div>

        {/* Opening Hours */}
        <div className="space-y-2">
          <Label className="text-sm font-medium">{t("landmark.openingHours", "开放时间")}</Label>
          <Input
            value={info.openingHoursInfo || ""}
            onChange={(e) => update("openingHoursInfo", e.target.value)}
            placeholder="08:00-18:00"
            className="h-8 text-sm"
          />
        </div>
      </div>

      {/* Transport */}
      <div className="space-y-2">
        <Label className="text-sm font-medium">{t("landmark.edit.fieldTransport", "交通方式")}</Label>
        <Input
          value={info.transport || ""}
          onChange={(e) => update("transport", e.target.value)}
          placeholder="公交1路 / Bus Line 1"
          className="h-8 text-sm"
        />
      </div>

      {/* Tips */}
      <div className="space-y-2">
        <Label className="text-sm font-medium">{t("landmark.edit.fieldTips", "注意事项")}</Label>
        <Textarea
          value={info.tips || ""}
          onChange={(e) => update("tips", e.target.value)}
          placeholder="建议穿舒适的鞋子..."
          className="min-h-[60px] text-sm"
        />
      </div>
    </div>
  );
}
