import { useEffect, useState } from "react";
import { useTranslation } from "react-i18next";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { useToast } from "@/hooks/use-toast";
import { Loader2, Plus, Sparkles, Trash2, Upload } from "lucide-react";

interface ChefRecommendedDishesEditorProps {
  restaurantId: string;
  mode?: "featured" | "signature" | "all";
}

type FeaturedDishRow = {
  id: string;
  restaurant_id: string;
  dish_name_zh: string;
  dish_name_en: string | null;
  dish_name_pt: string | null;
  description_zh: string | null;
  description_en: string | null;
  description_pt: string | null;
  neijing_zh: string | null;
  neijing_en: string | null;
  neijing_pt: string | null;
  image_url: string | null;
  sort_order: number | null;
  isSaving?: boolean;
  isUploading?: boolean;
  isGenerating?: boolean;
};

type SignatureDishRow = {
  id: string;
  restaurant_id: string;
  dish_name_zh: string;
  dish_name_en: string | null;
  dish_name_pt: string | null;
  description_zh: string | null;
  description_en: string | null;
  description_pt: string | null;
  neijing_zh: string | null;
  neijing_en: string | null;
  neijing_pt: string | null;
  image_url: string | null;
  sort_order: number | null;
};

type EditableSignatureDish = SignatureDishRow & {
  isNew?: boolean;
  isSaving?: boolean;
  isDeleting?: boolean;
  isUploading?: boolean;
};

const createEmptyDish = (restaurantId: string, sortOrder: number): EditableSignatureDish => ({
  id: `new-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
  restaurant_id: restaurantId,
  dish_name_zh: "",
  dish_name_en: "",
  dish_name_pt: "",
  description_zh: "",
  description_en: "",
  description_pt: "",
  neijing_zh: "",
  neijing_en: "",
  neijing_pt: "",
  image_url: null,
  sort_order: sortOrder,
  isNew: true,
});

export function ChefRecommendedDishesEditor({ restaurantId, mode = "all" }: ChefRecommendedDishesEditorProps) {
  const { t } = useTranslation();
  const { toast } = useToast();
  const [featuredDishes, setFeaturedDishes] = useState<FeaturedDishRow[]>([]);
  const [dishes, setDishes] = useState<EditableSignatureDish[]>([]);
  const [loading, setLoading] = useState(true);
  const showFeatured = mode === "featured" || mode === "all";
  const showSignature = mode === "signature" || mode === "all";

  useEffect(() => {
    const fetchDishes = async () => {
      setLoading(true);
      const [featuredRes, signatureRes] = await Promise.all([
        showFeatured
          ? supabase
              .from("chef_recommended_dishes")
              .select("id, restaurant_id, dish_name_zh, dish_name_en, dish_name_pt, description_zh, description_en, description_pt, neijing_zh, neijing_en, neijing_pt, image_url, sort_order")
              .eq("restaurant_id", restaurantId)
              .order("sort_order", { ascending: true })
          : Promise.resolve({ data: [], error: null }),
        showSignature
          ? supabase
              .from("chef_signature_dishes" as any)
              .select("id, restaurant_id, dish_name_zh, dish_name_en, dish_name_pt, description_zh, description_en, description_pt, neijing_zh, neijing_en, neijing_pt, image_url, sort_order")
              .eq("restaurant_id", restaurantId)
              .order("sort_order", { ascending: true })
          : Promise.resolve({ data: [], error: null }),
      ]);

      if (showFeatured) {
        if (featuredRes.error) {
          toast({ title: t("common.error"), description: featuredRes.error.message, variant: "destructive" });
        } else {
          setFeaturedDishes((featuredRes.data ?? []) as FeaturedDishRow[]);
        }
      }

      if (showSignature) {
        if (signatureRes.error) {
          toast({ title: t("common.error"), description: signatureRes.error.message, variant: "destructive" });
        } else {
          setDishes((signatureRes.data ?? []) as EditableSignatureDish[]);
        }
      }

      setLoading(false);
    };

    void fetchDishes();
  }, [restaurantId, showFeatured, showSignature, t, toast]);

  const updateFeaturedDish = (dishId: string, updates: Partial<FeaturedDishRow>) => {
    setFeaturedDishes((prev) => prev.map((dish) => (dish.id === dishId ? { ...dish, ...updates } : dish)));
  };

  const updateDish = (dishId: string, updates: Partial<EditableSignatureDish>) => {
    setDishes((prev) => prev.map((dish) => (dish.id === dishId ? { ...dish, ...updates } : dish)));
  };

  const addDish = () => {
    setDishes((prev) => [...prev, createEmptyDish(restaurantId, prev.length)]);
  };

  const uploadImageToBucket = async (prefix: string, file: File) => {
    const fileExt = file.name.split(".").pop() || "jpg";
    const fileName = `${prefix}-${restaurantId}-${Date.now()}.${fileExt}`;
    const { error: uploadError } = await supabase.storage.from("restaurant-images").upload(fileName, file);
    if (uploadError) throw uploadError;
    const { data } = supabase.storage.from("restaurant-images").getPublicUrl(fileName);
    return data.publicUrl;
  };

  const uploadFeaturedImage = async (dishId: string, file: File) => {
    if (!file.type.startsWith("image/")) {
      toast({ title: t("common.error"), description: t("admin.invalidImage", "请选择图片文件"), variant: "destructive" });
      return;
    }

    updateFeaturedDish(dishId, { isUploading: true });
    try {
      const publicUrl = await uploadImageToBucket("chef-featured", file);
      updateFeaturedDish(dishId, { image_url: publicUrl });
    } catch (error: any) {
      toast({ title: t("common.error"), description: error.message || t("admin.uploadFailed", "上传失败"), variant: "destructive" });
    } finally {
      updateFeaturedDish(dishId, { isUploading: false });
    }
  };

  const uploadSignatureImage = async (dishId: string, file: File) => {
    if (!file.type.startsWith("image/")) {
      toast({ title: t("common.error"), description: t("admin.invalidImage", "请选择图片文件"), variant: "destructive" });
      return;
    }

    updateDish(dishId, { isUploading: true });
    try {
      const publicUrl = await uploadImageToBucket("chef-signature-dish", file);
      updateDish(dishId, { image_url: publicUrl });
    } catch (error: any) {
      toast({ title: t("common.error"), description: error.message || t("admin.uploadFailed", "上传失败"), variant: "destructive" });
    } finally {
      updateDish(dishId, { isUploading: false });
    }
  };

  const saveFeaturedDish = async (dish: FeaturedDishRow) => {
    updateFeaturedDish(dish.id, { isSaving: true });

    const normalizedName = dish.dish_name_zh?.trim() || null;
    const normalizedDescription = dish.description_zh?.trim() || null;
    const normalizedNeijing = dish.neijing_zh?.trim() || null;

    const payload = {
      dish_name_zh: normalizedName,
      dish_name_en: normalizedName,
      dish_name_pt: normalizedName,
      description_zh: normalizedDescription,
      description_en: normalizedDescription,
      description_pt: normalizedDescription,
      neijing_zh: normalizedNeijing,
      neijing_en: normalizedNeijing,
      neijing_pt: normalizedNeijing,
      image_url: dish.image_url || null,
    };

    const { error } = await supabase.from("chef_recommended_dishes").update(payload).eq("id", dish.id);

    if (error) {
      toast({ title: t("common.error"), description: error.message || t("admin.saveFailed", "保存失败"), variant: "destructive" });
      updateFeaturedDish(dish.id, { isSaving: false });
      return;
    }

    updateFeaturedDish(dish.id, { isSaving: false });
    toast({ title: t("common.success"), description: t("admin.featuredDishSaved", "顶部内容已保存") });
  };

  const generateFeaturedContent = async (dish: FeaturedDishRow, mode: "all" | "neijing" = "all") => {
    updateFeaturedDish(dish.id, { isGenerating: true });

    try {
      const { data, error } = await supabase.functions.invoke("generate-chef-featured-content", {
        body: { restaurant_id: restaurantId, featured_id: dish.id, mode },
      });

      if (error) throw error;

      updateFeaturedDish(dish.id, mode === "neijing" ? {
        neijing_zh: data?.neijing_zh || dish.neijing_zh,
        neijing_en: data?.neijing_en || dish.neijing_en,
        neijing_pt: data?.neijing_pt || dish.neijing_pt,
      } : {
        dish_name_zh: data?.dish_name_zh || dish.dish_name_zh,
        dish_name_en: data?.dish_name_en || dish.dish_name_en,
        dish_name_pt: data?.dish_name_pt || dish.dish_name_pt,
        description_zh: data?.description_zh || dish.description_zh,
        description_en: data?.description_en || dish.description_en,
        description_pt: data?.description_pt || dish.description_pt,
        neijing_zh: data?.neijing_zh || dish.neijing_zh,
        neijing_en: data?.neijing_en || dish.neijing_en,
        neijing_pt: data?.neijing_pt || dish.neijing_pt,
      });

      toast({ title: t("common.success"), description: mode === "neijing" ? t("admin.neijingGenerated", "黄帝内经解读已重新生成") : t("admin.featuredDishGenerated", "顶部内容已重新生成") });
    } catch (error: any) {
      toast({ title: t("common.error"), description: error.message || t("admin.generateFailed", "生成失败"), variant: "destructive" });
    } finally {
      updateFeaturedDish(dish.id, { isGenerating: false });
    }
  };

  const saveDish = async (dish: EditableSignatureDish) => {
    if (!dish.dish_name_zh.trim()) {
      toast({ title: t("common.error"), description: t("admin.signatureDishNameRequired", "请填写招牌菜中文名"), variant: "destructive" });
      return;
    }

    updateDish(dish.id, { isSaving: true });
    const normalizedName = dish.dish_name_zh.trim();
    const normalizedDescription = dish.description_zh?.trim() || null;
    const normalizedDetail = dish.neijing_zh?.trim() || null;

    const payload = {
      restaurant_id: restaurantId,
      dish_name_zh: normalizedName,
      dish_name_en: normalizedName,
      dish_name_pt: normalizedName,
      description_zh: normalizedDescription,
      description_en: normalizedDescription,
      description_pt: normalizedDescription,
      neijing_zh: normalizedDetail,
      neijing_en: normalizedDetail,
      neijing_pt: normalizedDetail,
      image_url: dish.image_url || null,
      sort_order: dish.sort_order ?? 0,
    };

    try {
      if (dish.isNew) {
        const { data, error } = await supabase
          .from("chef_signature_dishes" as any)
          .insert(payload)
          .select("id, restaurant_id, dish_name_zh, dish_name_en, dish_name_pt, description_zh, description_en, description_pt, neijing_zh, neijing_en, neijing_pt, image_url, sort_order")
          .single();

        if (error) throw error;
        setDishes((prev) => prev.map((item) => (item.id === dish.id ? ({ ...((data as unknown) as SignatureDishRow) } as EditableSignatureDish) : item)));
      } else {
        const { error } = await supabase.from("chef_signature_dishes" as any).update(payload).eq("id", dish.id);
        if (error) throw error;
      }

      toast({ title: t("common.success"), description: t("admin.signatureDishSaved", "招牌菜已保存") });
    } catch (error: any) {
      toast({ title: t("common.error"), description: error.message || t("admin.saveFailed", "保存失败"), variant: "destructive" });
      updateDish(dish.id, { isSaving: false });
      return;
    }

    updateDish(dish.id, { isSaving: false, isNew: false });
  };

  const deleteDish = async (dish: EditableSignatureDish) => {
    if (dish.isNew) {
      setDishes((prev) => prev.filter((item) => item.id !== dish.id));
      return;
    }

    updateDish(dish.id, { isDeleting: true });
    const { error } = await supabase.from("chef_signature_dishes" as any).delete().eq("id", dish.id);
    if (error) {
      toast({ title: t("common.error"), description: error.message, variant: "destructive" });
      updateDish(dish.id, { isDeleting: false });
      return;
    }

    setDishes((prev) => prev.filter((item) => item.id !== dish.id));
    toast({ title: t("common.success"), description: t("admin.signatureDishDeleted", "招牌菜已删除") });
  };

  if (loading) {
    return (
      <Card className="border-primary/20">
        <CardContent className="flex items-center justify-center p-6">
          <Loader2 className="h-5 w-5 animate-spin text-primary" />
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-6">
      {showFeatured && (
        <div className="space-y-4">
          <div>
            <Label className="text-base font-semibold">{t("admin.featuredDishIntro", "顶部主叙事区")}</Label>
            <p className="mt-1 text-xs text-muted-foreground">
              {t("admin.featuredDishIntroHint", "这里控制餐厅详情页顶部主视觉区域：大图、主标题、内容介绍，以及展开后看到的《黄帝内经》解读。")}
            </p>
          </div>

          {featuredDishes.length === 0 ? (
            <Card className="border-primary/20 border-dashed">
              <CardContent className="p-6 text-center text-sm text-muted-foreground">
                {t("admin.noFeaturedDishIntro", "顶部主叙事区暂无内容")}
              </CardContent>
            </Card>
          ) : (
            featuredDishes.map((dish, index) => (
              <Card key={dish.id} className="border-primary/20">
                <CardContent className="space-y-4 p-5">
                  <div className="flex items-start justify-between gap-3">
                    <div>
                      <Label className="text-sm font-medium">{t("admin.featuredDishIntroItem", "顶部主叙事")} #{index + 1}</Label>
                      <p className="mt-1 text-xs text-muted-foreground">对应详情页顶部图片区域与展开说明，不是下方招牌菜列表。</p>
                    </div>
                  </div>

                  <div className="space-y-3">
                    <Label>{t("admin.signatureDishImage", "顶部图片")}</Label>
                    <p className="text-xs text-muted-foreground">显示在详情页顶部主视觉位置，可放餐厅图，也可放代表性菜品图。</p>
                    <div className="flex items-start gap-3">
                      {dish.image_url ? (
                        <img src={dish.image_url} alt={dish.dish_name_zh || `featured-${index + 1}`} className="h-28 w-28 rounded-xl border border-border object-cover" />
                      ) : (
                        <div className="flex h-28 w-28 items-center justify-center rounded-xl border border-dashed border-border px-2 text-center text-xs text-muted-foreground">
                          {t("admin.optionalImage", "可上传餐厅图或招牌菜图")}
                        </div>
                      )}
                      <div className="flex-1 space-y-2">
                        <Input value={dish.image_url || ""} onChange={(e) => updateFeaturedDish(dish.id, { image_url: e.target.value })} placeholder={t("admin.featuredImagePlaceholder", "可填写餐厅图片或招牌菜图片链接")} />
                        <Label className="inline-flex cursor-pointer">
                          <Input type="file" accept="image/*" className="hidden" onChange={(e) => {
                            const file = e.target.files?.[0];
                            if (file) void uploadFeaturedImage(dish.id, file);
                          }} />
                          <span className="inline-flex items-center rounded-md border border-input bg-background px-3 py-2 text-sm transition-colors hover:bg-accent hover:text-accent-foreground">
                            {dish.isUploading ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Upload className="mr-2 h-4 w-4" />}
                            {t("admin.uploadImage", "上传图片")}
                          </span>
                        </Label>
                      </div>
                    </div>
                  </div>

                  <div className="space-y-2">
                    <Label>{t("admin.featuredTitle", "顶部主标题")}</Label>
                    <p className="text-xs text-muted-foreground">显示在详情页顶部图片上的主标题。</p>
                    <Input value={dish.dish_name_zh || ""} onChange={(e) => updateFeaturedDish(dish.id, { dish_name_zh: e.target.value })} placeholder={t("admin.featuredTitlePlaceholder", "可写餐厅主题标题或招牌菜标题")} />
                  </div>

                  <div className="space-y-2">
                    <Label>{t("admin.dishIntro", "顶部内容介绍")}</Label>
                    <p className="text-xs text-muted-foreground">显示在顶部主视觉下方，同时作为《黄帝内经》解读的生成基础。</p>
                    <Textarea value={dish.description_zh || ""} onChange={(e) => updateFeaturedDish(dish.id, { description_zh: e.target.value })} rows={4} placeholder={t("admin.featuredDescriptionPlaceholder", "这段介绍会作为顶部图片区下方内容，也会作为黄帝内经自动生成基础")} />
                  </div>

                  <div className="space-y-2">
                    <div className="flex items-center justify-between gap-3">
                      <Label>{t("admin.neijingInterpretation", "《黄帝内经》解读（展开后显示）")}</Label>
                      <Button type="button" variant="outline" size="sm" onClick={() => generateFeaturedContent(dish, "neijing")} disabled={dish.isGenerating}>
                        {dish.isGenerating ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Sparkles className="mr-2 h-4 w-4" />}
                        {t("admin.regenerateNeijing", "重新生成黄帝内经解读")}
                      </Button>
                    </div>
                    <p className="text-xs text-muted-foreground">
                      {t("admin.featuredNeijingCurrentHint", "这部分不会直接铺在顶部图上，而是用户展开后看到的《黄帝内经》解读；若为空，说明当前还没有生成或保存。")}
                    </p>
                    <Textarea value={dish.neijing_zh || ""} onChange={(e) => updateFeaturedDish(dish.id, { neijing_zh: e.target.value })} rows={6} placeholder={t("admin.featuredNeijingPlaceholder", "这里显示《黄帝内经》解读内容，可点击重新生成后再手动修改")} />
                  </div>

                  <div className="flex justify-end">
                    <Button type="button" onClick={() => saveFeaturedDish(dish)} disabled={dish.isSaving || dish.isUploading || dish.isGenerating}>
                      {dish.isSaving ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : null}
                      {t("common.save", "保存")}
                    </Button>
                  </div>
                </CardContent>
              </Card>
            ))
          )}
        </div>
      )}

      {showSignature && (
        <div className="space-y-4">
          <div className="flex items-center justify-between gap-3">
            <div>
              <Label className="text-base font-semibold">{t("admin.signatureDishes", "下方招牌菜品")}</Label>
              <p className="mt-1 text-xs text-muted-foreground">{t("admin.signatureDishesHint", "这里是新的独立字段，专门控制页面下方招牌菜列表")}</p>
            </div>
            <Button type="button" variant="outline" size="sm" onClick={addDish}>
              <Plus className="mr-1 h-4 w-4" />
              {t("admin.addSignatureDish", "新增招牌菜")}
            </Button>
          </div>

          {dishes.length === 0 && (
            <Card className="border-primary/20 border-dashed">
              <CardContent className="p-6 text-center text-sm text-muted-foreground">
                {t("admin.noSignatureDishes", "暂无招牌菜，点击右上角新增")}
              </CardContent>
            </Card>
          )}

          {dishes.map((dish, index) => (
            <Card key={dish.id} className="border-primary/20">
              <CardContent className="space-y-4 p-5">
                <div className="flex items-center justify-between gap-3">
                  <Label className="text-sm font-medium">{t("admin.signatureDishNumber", "招牌菜")} #{index + 1}</Label>
                  <Button type="button" variant="ghost" size="icon" className="text-destructive hover:text-destructive" onClick={() => deleteDish(dish)} disabled={dish.isDeleting}>
                    {dish.isDeleting ? <Loader2 className="h-4 w-4 animate-spin" /> : <Trash2 className="h-4 w-4" />}
                  </Button>
                </div>

                <div className="space-y-2">
                  <Label>{t("admin.signatureDishName", "菜名")}</Label>
                  <Input value={dish.dish_name_zh} onChange={(e) => updateDish(dish.id, { dish_name_zh: e.target.value })} placeholder={t("admin.signatureDishNamePlaceholder", "只需填写一种语言")} />
                </div>

                <div className="space-y-3">
                  <Label>{t("admin.signatureDishImage", "菜品图片（可选）")}</Label>
                  <div className="flex items-start gap-3">
                    {dish.image_url ? (
                      <img src={dish.image_url} alt={dish.dish_name_zh || `dish-${index + 1}`} className="h-24 w-24 rounded-lg border border-border object-cover" />
                    ) : (
                      <div className="flex h-24 w-24 items-center justify-center rounded-lg border border-dashed border-border px-2 text-center text-xs text-muted-foreground">
                        {t("admin.optionalImage", "可不上传")}
                      </div>
                    )}
                    <div className="flex-1 space-y-2">
                      <Input value={dish.image_url || ""} onChange={(e) => updateDish(dish.id, { image_url: e.target.value })} placeholder={t("admin.imageUrlOptional", "图片链接（可选）")} />
                      <Label className="inline-flex cursor-pointer">
                        <Input type="file" accept="image/*" className="hidden" onChange={(e) => {
                          const file = e.target.files?.[0];
                          if (file) void uploadSignatureImage(dish.id, file);
                        }} />
                        <span className="inline-flex items-center rounded-md border border-input bg-background px-3 py-2 text-sm transition-colors hover:bg-accent hover:text-accent-foreground">
                          {dish.isUploading ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Upload className="mr-2 h-4 w-4" />}
                          {t("admin.uploadImage", "上传图片")}
                        </span>
                      </Label>
                    </div>
                  </div>
                </div>

                <div className="space-y-2">
                  <Label>{t("admin.dishIntro", "菜品简介")}</Label>
                  <Textarea value={dish.description_zh || ""} onChange={(e) => updateDish(dish.id, { description_zh: e.target.value })} rows={3} placeholder={t("admin.signatureDishDescriptionPlaceholder", "只需填写一种语言")} />
                </div>

                <div className="space-y-2">
                  <Label>{t("admin.dishDetailZh", "菜品详解 / 黄帝内经基础内容")}</Label>
                  <Textarea value={dish.neijing_zh || ""} onChange={(e) => updateDish(dish.id, { neijing_zh: e.target.value })} rows={5} placeholder={t("admin.dishDetailZhPlaceholder", "只需填写一种语言，黄帝内经可基于此生成")} />
                </div>

                <div className="flex justify-end">
                  <Button type="button" onClick={() => saveDish(dish)} disabled={dish.isSaving || dish.isUploading}>
                    {dish.isSaving ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : null}
                    {t("common.save", "保存")}
                  </Button>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}
    </div>
  );
}
